function FoodImg({ id, title, style={}, textSize=32, customImg=null }) {
  if (customImg) return <div style={{ backgroundImage:`url(${customImg})`, backgroundSize:"cover", backgroundPosition:"center", flexShrink:0, ...style }}/>;
  const [light, mid, emoji] = PALETTE[id] || PALETTE.default;
  const initials = (title||"").split(" ").slice(0,2).map(w=>w[0]).join("").toUpperCase()||"?";
  return (
    <div style={{ background:`linear-gradient(135deg,${light} 0%,${mid} 100%)`, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:6, overflow:"hidden", flexShrink:0, ...style }}>
      <span style={{ fontSize:textSize, lineHeight:1 }}>{emoji}</span>
      <span style={{ fontSize:Math.max(8,textSize*0.28), color:"rgba(0,0,0,0.15)", letterSpacing:2, textTransform:"uppercase", fontFamily:"'Nunito',sans-serif" }}>{initials}</span>
    </div>
  );
}

// ── AI ────────────────────────────────────────────────────────────────────────
async function askAI(messages, system="", signal=null) {
  const url = "/.netlify/functions/claude";
  try {
    const res = await fetch(url, {
      method:"POST",
      headers:{"Content-Type":"application/json"},
      signal,
      body: JSON.stringify({ model:"claude-sonnet-4-5-20250929", max_tokens:1000, system, messages }),
    });
    if(!res.ok) { console.error("API error:", res.status, await res.text()); return ""; }
    const data = await res.json();
    return data.content?.[0]?.text || "";
  } catch(e) {
    if(e.name==="AbortError") return "__ABORTED__";
    console.error("askAI error:", e);
    return "";
  }
}
async function suggestTags(title, ingredients) {
  const system = `Du är en matassistent. Returnera ENDAST ett JSON-array (ingen markdown) med 1-3 taggar från: ${ALL_CATS.join(", ")}.`;
  const text = await askAI([{ role:"user", content:`Rätt: ${title}. Ingredienser: ${ingredients||""}` }], system);
  try { return JSON.parse(text.replace(/```json|```/g,"").trim()); } catch { return ["övrigt"]; }
}
async function getRecipeMeta(recipe) {
  const system = `Du är en kunnig kock. Returnera ENDAST ett JSON-objekt (ingen markdown) med: tips (array 2-3 korta tips, max 15 ord), drinks (array 2 objekt med name och why, max 12 ord), variation (string max 20 ord).`;
  const text = await askAI([{ role:"user", content:`Recept: ${recipe.title}. Ingredienser: ${recipe.ingredients?.join(", ")||""}` }], system);
  try { return JSON.parse(text.replace(/```json|```/g,"").trim()); } catch { return null; }
}
async function buildWeekShoppingList(allIngredients) {
  // Pre-merge: group by base name ignoring amounts
  const seen = {};
  const deduped = [];
  allIngredients.forEach(ing => {
    const base = ing.replace(/^[\d\s.,/-]+(g|kg|ml|l|dl|msk|tsk|st|cl|krm|burk|)?\s*/i, "").trim().toLowerCase().replace(/^(ca |ca\. )/, "");
    if (!seen[base]) { seen[base] = true; deduped.push(ing); }
  });
  const system = `Du är en matassistent. Returnera ENDAST ett JSON-objekt (ingen markdown) med kategorier som nycklar och ingredient-arrays. Kategorier: "Frukt & grönt", "Mejeri & ägg", "Kött & fisk", "Torrvaror & pasta", "Konserver & såser", "Kryddor & oljor", "Övrigt". Summera mängder där det är uppenbart.`;
  const text = await askAI([{ role:"user", content:"Kategorisera: "+deduped.join(", ") }], system);
  try { return JSON.parse(text.replace(/\`\`\`json|\`\`\`/g,"").trim()); } catch { return { "Alla ingredienser": deduped }; }
}
async function importFromUrl(url, signal=null) {
  // Try to fetch page content first, fall back to just sending URL
  let pageText = "";
  try {
    const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`;
    const r = await fetch(proxyUrl, { signal });
    if(r.ok) {
      const j = await r.json();
      // Strip HTML tags and trim to ~3000 chars
      pageText = (j.contents || "").replace(/<[^>]+>/g," ").replace(/\s+/g," ").trim().slice(0,3000);
    }
  } catch(e) {
    if(e.name==="AbortError") return "__ABORTED__";
  }
  const content = pageText
    ? `Extrahera receptet från denna text (hämtad från ${url}):\n\n${pageText}`
    : `Importera recept från denna URL: ${url}`;
  return askAI([{ role:"user", content }],
    `Returnera ENDAST ett JSON-objekt (ingen markdown): { title, servings, ingredients (array), instructions (array) }`,
    signal);
}

// ── Image library ─────────────────────────────────────────────────────────────
const LIB_KEY = "kokbok_imglib_v1";
function loadLibrary() {
  try { const r=localStorage.getItem(LIB_KEY); if(r) return JSON.parse(r); } catch {}
  saveLibrary(BUILTIN_LIBRARY);
  return BUILTIN_LIBRARY;
}
function saveLibrary(lib) { try { localStorage.setItem(LIB_KEY, JSON.stringify(lib)); } catch {} }

async function matchImageFromLibrary(title, ingredients, library) {
  if (!library.length) return null;
  const names = library.map(img => img.name).join(", ");
  const system = `Du är en matassistent. Du får ett recept och en lista med bildnamn. Returnera ENDAST ett av dessa bildnamn (exakt stavning) som passar bäst som illustration. Välj baserat på huvudingrediens eller rätt. Svara "none" om inget passar.`;
  const text = await askAI([{ role:"user", content:`Recept: "${title}". Ingredienser: ${ingredients}.\nTillgängliga bilder: ${names}` }], system);
  const match = text.trim().replace(/['"]/g,"").split("\n")[0].trim();
  if (match === "none") return null;
  return library.find(img => img.name === match) || null;
}
async function importFromImageBase64(base64, mimeType, signal) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 30000);
  const effectiveSignal = signal || controller.signal;
  const url = "/.netlify/functions/claude";
  try {
    const res = await fetch(url, {
      method:"POST", headers:{"Content-Type":"application/json"},
      signal: effectiveSignal,
      body: JSON.stringify({ model:"claude-sonnet-4-5-20250929", max_tokens:1500,
        system:`Läs av receptet i bilden. Returnera ENDAST JSON: { title, servings, ingredients (array), instructions (array) }`,
        messages:[{ role:"user", content:[{ type:"image", source:{ type:"base64", media_type:mimeType, data:base64 }},{ type:"text", text:"Läs av receptet." }]}],
      }),
    });
    clearTimeout(timeout);
    const data = await res.json();
    return data.content?.[0]?.text || "";
  } catch(e) {
    clearTimeout(timeout);
    if (e.name === "AbortError") return "__ABORTED__";
    throw e;
  }
}

