// ── Image Picker ─────────────────────────────────────────────────────────────
function ImagePicker({ value, onChange, library }) {
  const [showLib, setShowLib] = useState(false);
  const fileRef = useRef();
  const handleFile = (file) => {
    if (!file) return;
    const r = new FileReader();
    r.onload = e => onChange({ name: file.name.replace(/\.[^.]+$/,""), src: e.target.result });
    r.readAsDataURL(file);
  };
  if (showLib) return (
    <div>
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:12}}>
        <button onClick={()=>setShowLib(false)} style={{fontSize:13,color:"#1a1a1a",background:"none",border:"none",cursor:"pointer"}}>← Tillbaka</button>
        <span style={{fontSize:13,color:"#333"}}>{library.length} bilder</span>
      </div>
      {library.length===0
        ? <p style={{fontSize:13,color:"#333",padding:"12px 0"}}>Biblioteket är tomt. Ladda upp bilder via "Bildbibliotek" på startsidan.</p>
        : <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
            {library.map(img=>(
              <div key={img.name} onClick={()=>{onChange(img);setShowLib(false);}}
                style={{cursor:"pointer",borderRadius:8,overflow:"hidden",border:value?.name===img.name?"2px solid #1a1a1a":"2px solid transparent",aspectRatio:"1",background:"#F7F4EE",display:"flex",alignItems:"center",justifyContent:"center"}}>
                <img src={img.src} style={{width:"100%",height:"100%",objectFit:"contain",padding:6}} alt={img.name}/>
              </div>
            ))}
          </div>}
    </div>
  );
  return (
    <div>
      {value?.src && (
        <div style={{position:"relative",marginBottom:10}}>
          <img src={value.src} style={{width:"100%",height:160,objectFit:"contain",borderRadius:8,background:"#F7F4EE",border:"1px solid #EAE6DF"}}/>
          <button onClick={()=>onChange(null)} style={S.imgRemove}>✕</button>
          <div style={{fontSize:12,color:"#333",marginTop:4,textAlign:"center"}}>{value.name}</div>
        </div>
      )}
      <div style={{display:"flex",gap:8}}>
        <button onClick={()=>fileRef.current.click()} style={{...S.imgUpload,flex:1,padding:"10px 8px",fontSize:12,margin:0}}>📁 Ladda upp</button>
        <button onClick={()=>setShowLib(true)} style={{...S.imgUpload,flex:1,padding:"10px 8px",fontSize:12,margin:0}}>🖼 Bibliotek{library.length>0?` (${library.length})`:""}</button>
      </div>
      <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={e=>handleFile(e.target.files[0])}/>
    </div>
  );
}

// ── Image Library View ────────────────────────────────────────────────────────
function AllRecipesView({ recipes, onBack, onRecipeClick }) {
  const [search, setSearch] = useState("");
  const all = Object.values(recipes).filter(r=>r.title).sort((a,b)=>a.title.localeCompare(b.title,"sv"));
  const filtered = search ? all.filter(r=>r.title.toLowerCase().includes(search.toLowerCase())) : all;
  return (
    <div>
      <button onClick={onBack} style={S.stickyBack}>←</button>
      <div style={S.view}>
        <ViewHeader src={ICON_GLOBE} title="Alla recept"/>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16,marginTop:8}}>
          <h2 style={{fontFamily:"'Libre Baskerville',serif",fontSize:22,fontWeight:700,color:"#1a1a1a",margin:0}}>Alla recept</h2>
        </div>
        <input style={{...S.formInput,marginBottom:16,fontSize:16}} placeholder="Sök recept..." value={search} onChange={e=>setSearch(e.target.value)}/>
        <div style={{borderTop:"1px solid #EAE6DF"}}>
          {filtered.map(r=>(
            <div key={r.id} onClick={()=>onRecipeClick(r)} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 0",borderBottom:"1px solid #EAE6DF",cursor:"pointer"}}>
              <FoodImg id={r.id} title={r.title} customImg={r.customImg} style={{width:48,height:48,borderRadius:8,border:"1px solid #EAE6DF",flexShrink:0}} textSize={18}/>
              <div style={{flex:1,minWidth:0}}>
                <p style={{fontSize:14,color:"#1a1a1a",fontWeight:500}}>{r.title}</p>
                <p style={{fontSize:12,color:"#333",marginTop:2}}>{r.tags?.join(", ")}</p>
              </div>
              <span style={{color:"#ccc",fontSize:18}}>›</span>
            </div>
          ))}
        </div>
        {filtered.length===0&&<p style={{fontSize:13,color:"#333",padding:"20px 0"}}>Inga recept hittades.</p>}
      </div>
    </div>
  );
}

function VeckomatView({ pool, recipes, onBack, onRecipeClick, onRemoveFromPool }) {
  const [filter, setFilter] = useState("alla");
  const filtered = filter==="alla"?pool:pool.filter(r=>r.tags?.includes(filter));
  return (
    <div>
      <button onClick={onBack} style={S.stickyBack}>←</button>
      <div style={S.view}>
        <ViewHeader src={ICON_MONEY} title="Veckomat"/>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8,marginTop:8}}>
          <h2 style={{fontFamily:"'Libre Baskerville',serif",fontSize:22,fontWeight:700,color:"#1a1a1a",margin:0}}>Veckomat</h2>
        </div>
        <p style={{fontSize:13,color:"#333",marginBottom:16}}>Recept som slumpas in i din veckoplanering.</p>
        <div style={{display:"flex",gap:6,overflowX:"auto",paddingBottom:4,marginBottom:16}}>
          {["alla",...ALL_CATS].map(cat=><button key={cat} onClick={()=>setFilter(cat)} style={{fontSize:12,padding:"5px 12px",borderRadius:12,border:"1px solid #E8E4DD",color:filter===cat?"#1a1a1a":"#333",background:filter===cat?"#F0EDE6":"#fff",flexShrink:0,cursor:"pointer"}}>{cat}</button>)}
        </div>
        <div style={{borderTop:"1px solid #EAE6DF"}}>
          {filtered.map(r=>{
            const full = recipes[r.id]||r;
            return (
              <div key={r.id} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 0",borderBottom:"1px solid #EAE6DF"}}>
                <div onClick={()=>onRecipeClick(full)} style={{cursor:"pointer",flexShrink:0}}>
                  <FoodImg id={r.id} title={r.title} customImg={full.customImg} style={{width:52,height:52,borderRadius:8,border:"1px solid #EAE6DF"}} textSize={20}/>
                </div>
                <div style={{flex:1,minWidth:0}} onClick={()=>onRecipeClick(full)}>
                  <p style={{fontSize:14,color:"#1a1a1a",fontWeight:500,marginBottom:3,cursor:"pointer"}}>{r.title}</p>
                  <div style={{display:"flex",flexWrap:"wrap",gap:4}}>{r.tags?.map(t=><span key={t} style={S.tagChipSm}>{t}</span>)}</div>
                </div>
                <button onClick={()=>onRemoveFromPool(r.id)} style={{fontSize:12,color:"#333",background:"none",border:"1px solid #E8E4DD",borderRadius:6,padding:"4px 8px",cursor:"pointer",flexShrink:0}}>Ta bort</button>
              </div>
            );
          })}
        </div>
        {filtered.length===0&&<p style={{fontSize:13,color:"#333",padding:"20px 0"}}>Inga recept med den kategorin.</p>}
      </div>
    </div>
  );
}

function ImageLibraryView({ library, onBack, onLibraryChange }) {
  const fileRef = useRef();
  const handleFiles = (files) => {
    let done = 0; const newImgs = [];
    [...files].forEach(file => {
      const r = new FileReader();
      r.onload = e => {
        newImgs.push({ name: file.name.replace(/\.[^.]+$/,""), src: e.target.result });
        done++;
        if (done === files.length) {
          const merged = [...library];
          newImgs.forEach(ni => { if (!merged.find(m=>m.name===ni.name)) merged.push(ni); });
          onLibraryChange(merged);
        }
      };
      r.readAsDataURL(file);
    });
  };
  const remove = (name) => { if(window.confirm(`Ta bort "${name}"?`)) onLibraryChange(library.filter(i=>i.name!==name)); };
  return (
    <div>
      <button onClick={onBack} style={S.stickyBack}>←</button>
      <div style={S.view}>
        <ViewHeader src={ICON_CAMERA} title="Bildbibliotek"/>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:6,marginTop:8}}>
          <h2 style={{fontFamily:"'Libre Baskerville',serif",fontSize:22,fontWeight:700,color:"#1a1a1a",margin:0}}>Bildbibliotek</h2>
        </div>
        <p style={{fontSize:12,color:"#1a1a1a",marginBottom:20}}>{library.length} bilder · AI väljer automatiskt vid nya recept</p>
        <button onClick={()=>fileRef.current.click()} style={{...S.primaryBtn,marginBottom:20}}>+ Lägg till bilder</button>
        <input ref={fileRef} type="file" accept="image/*" multiple style={{display:"none"}} onChange={e=>handleFiles(e.target.files)}/>
        <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10}}>
          {library.map(img=>(
            <div key={img.name} style={{position:"relative"}}>
              <div style={{aspectRatio:"1",background:"#F7F4EE",borderRadius:10,overflow:"hidden",border:"1px solid #EAE6DF",display:"flex",alignItems:"center",justifyContent:"center"}}>
                <img src={img.src} style={{width:"100%",height:"100%",objectFit:"contain",padding:6}} alt={img.name}/>
              </div>
              <p style={{fontSize:13,color:"#333",marginTop:4,textAlign:"center",letterSpacing:.5,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{img.name}</p>
              <button onClick={()=>remove(img.name)} style={{position:"absolute",top:4,right:4,width:20,height:20,borderRadius:"50%",background:"rgba(255,255,255,0.9)",border:"1px solid #ddd",fontSize:12,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",color:"#333"}}>✕</button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── Tag Editor ────────────────────────────────────────────────────────────────
function TagEditor({ tags, onChange }) {
  const [custom, setCustom] = useState("");
  const toggle = cat => onChange(tags.includes(cat) ? tags.filter(t=>t!==cat) : [...tags, cat]);
  const addCustom = () => { const t=custom.trim().toLowerCase(); if(t&&!tags.includes(t)) onChange([...tags,t]); setCustom(""); };
  return (
    <div>
      <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:8}}>
        {ALL_CATS.map(cat=>(
          <button key={cat} onClick={()=>toggle(cat)} style={{...S.tagToggle,...(tags.includes(cat)?S.tagToggleOn:{})}}>{cat}</button>
        ))}
        {tags.filter(t=>!ALL_CATS.includes(t)).map(t=>(
          <button key={t} onClick={()=>toggle(t)} style={{...S.tagToggle,...S.tagToggleOn}}>{t} ✕</button>
        ))}
      </div>
      <div style={{display:"flex",gap:8,marginTop:4}}>
        <input style={{...S.formInput,flex:1,padding:"7px 10px",fontSize:13}} value={custom} onChange={e=>setCustom(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addCustom()} placeholder="Egen tagg…"/>
        <button onClick={addCustom} style={S.tagAddBtn}>+</button>
      </div>
    </div>
  );
}

// ── Import Modal ──────────────────────────────────────────────────────────────
function ImportModal({ onClose, onImported, library, collections }) {
  const [step, setStep] = useState("menu");
  const [url, setUrl] = useState("");
  const [draft, setDraft] = useState({ title:"", servings:4, ingredients:"", instructions:"", customImg:null, sourceName:"", sourceUrl:"", tags:[], targetCollection:"" });
  const [tagsLoading, setTagsLoading] = useState(false);
  const [error, setError] = useState("");
  const fileRef = useRef(); const cameraRef = useRef(); const abortRef = useRef(null);

  const parseAndEdit = async (jsonText, sourceUrl="") => {
    try {
      if(!jsonText || jsonText==="__ABORTED__") { setStep("menu"); return; }
      const p = JSON.parse(jsonText.replace(/```json|```/g,"").trim());
      setDraft({ title:p.title||"", servings:p.servings||4, ingredients:Array.isArray(p.ingredients)?p.ingredients.join("\n"):p.ingredients||"", instructions:Array.isArray(p.instructions)?p.instructions.join("\n"):p.instructions||"", customImg:null, sourceName:"", sourceUrl, tags:[] });
      setStep("edit"); setTagsLoading(true);
      const ingStr = Array.isArray(p.ingredients)?p.ingredients.join(", "):"";
      const [suggested, matchedImg] = await Promise.all([
        suggestTags(p.title, ingStr),
        matchImageFromLibrary(p.title, ingStr, library),
      ]);
      setDraft(d=>({...d, tags:suggested, customImg:matchedImg||null}));
      setTagsLoading(false);
    } catch(e) {
      if(e.name==="AbortError") { setStep("menu"); return; }
      setError("Kunde inte tolka receptet. Fyll i manuellt.");
      setStep("manual");
    }
  };
  const handleUrlImport = async () => {
    if(!url.trim())return; setStep("loading"); setError("");
    abortRef.current = new AbortController();
    const tid = setTimeout(()=>abortRef.current?.abort(), 30000);
    try {
      const res = await importFromUrl(url, abortRef.current.signal);
      clearTimeout(tid);
      if(res === "__ABORTED__") { setStep("menu"); return; }
      parseAndEdit(res, url);
    } catch(e) { clearTimeout(tid); setError("Anslutningen avbröts. Försök igen."); setStep("url"); }
  };
  const handleFileImport = async (file) => {
    if(!file)return; setStep("loading"); setError("");
    abortRef.current = new AbortController();
    const reader=new FileReader();
    reader.onload=async e=>{
      const result = await importFromImageBase64(e.target.result.split(",")[1], file.type, abortRef.current.signal);
      if(result === "__ABORTED__") { setStep("menu"); return; }
      parseAndEdit(result);
    };
    reader.readAsDataURL(file);
  };
  const handleAbort = () => {
    abortRef.current?.abort();
    setStep("menu");
  };
  const save = () => {
    const id="r"+Date.now();
    onImported({ id, title:draft.title, servings:Number(draft.servings),
      customImg:draft.customImg?.src||null, customImgName:draft.customImg?.name||null,
      sourceName:draft.sourceName, sourceUrl:draft.sourceUrl, tags:draft.tags,
      ingredients:draft.ingredients.split("\n").map(s=>s.trim()).filter(Boolean),
      instructions:draft.instructions.split("\n").map(s=>s.trim()).filter(Boolean),
    }, draft.targetCollection); onClose();
  };

  return (
    <div style={S.modalBg}>
      <div style={{...S.modalBox,maxHeight:"88vh",overflowY:"auto"}}>
        {step==="menu"&&<>
          <div style={S.modalHead}><span style={S.eyebrow}>IMPORTERA RECEPT</span><button onClick={onClose} style={S.iconBtn}>✕</button></div>
          <div style={{paddingBottom:16}}>
            {[{icon:"🖼",label:"Importera bild",sub:"Foto på kokbokssida",action:()=>fileRef.current.click()},{icon:"📷",label:"Ta en bild",sub:"Använd kameran",action:()=>cameraRef.current.click()},{icon:"🔗",label:"Importera länk",sub:"Webbsida eller Instagram",action:()=>setStep("url")},{icon:"📋",label:"Klistra in text",sub:"Kopiera text från webbsida eller app",action:()=>setStep("paste")},
              {icon:"✏️",label:"Skriv in manuellt",sub:"Fyll i själv",action:()=>setStep("manual")}].map(item=>(
              <button key={item.label} onClick={item.action} style={{display:"flex",alignItems:"center",gap:14,width:"100%",padding:"14px 20px",textAlign:"left",borderBottom:"1px solid #F7F4EE",background:"none",border:"none",cursor:"pointer",borderBottom:"1px solid #F7F4EE"}}>
                <span style={{fontSize:22,flexShrink:0}}>{item.icon}</span>
                <div><div style={{fontSize:14,color:"#1a1a1a",marginBottom:2,fontWeight:500}}>{item.label}</div><div style={{fontSize:12,color:"#1a1a1a"}}>{item.sub}</div></div>
                <span style={{marginLeft:"auto",color:"#1a1a1a",fontSize:16}}>→</span>
              </button>
            ))}
          </div>
          <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={e=>handleFileImport(e.target.files[0])}/>
          <input ref={cameraRef} type="file" accept="image/*" capture="environment" style={{display:"none"}} onChange={e=>handleFileImport(e.target.files[0])}/>
        </>}
        {(step==="paste")&&<>
          <div style={S.modalHead}><button onClick={()=>setStep("menu")} style={S.iconBtn}>←</button><span style={S.eyebrow}>KLISTRA IN TEXT</span><button onClick={onClose} style={S.iconBtn}>✕</button></div>
          <div style={{padding:"16px 20px 20px"}}>
            <textarea style={{...S.formInput,height:160,resize:"none",marginBottom:12}} placeholder="Klistra in recepttext här — fungerar med Instagram, matbloggar m.m." value={url} onChange={e=>setUrl(e.target.value)}/>
            <button style={S.primaryBtn} disabled={!url.trim()} onClick={async()=>{
              setStep("loading"); setError("");
              const text = await askAI([{role:"user",content:"Extrahera receptet från denna text:\n\n"+url.slice(0,4000)}], "Returnera ENDAST ett JSON-objekt (ingen markdown): { title, servings, ingredients (array), instructions (array) }");
              parseAndEdit(text);
            }}>Importera</button>
          </div>
        </>}
        {step==="url"&&<>
          <div style={S.modalHead}><button onClick={()=>setStep("menu")} style={S.iconBtn}>←</button><span style={S.eyebrow}>KLISTRA IN LÄNK</span><button onClick={onClose} style={S.iconBtn}>✕</button></div>
          <div style={{padding:"16px 20px 20px"}}>
              <input style={S.formInput} value={url} onChange={e=>setUrl(e.target.value)} placeholder="https://..." onKeyDown={e=>e.key==="Enter"&&handleUrlImport()}/>
              <p style={{fontSize:12,color:"#333",marginTop:8,marginBottom:12}}>Tips: Instagram-länkar funkar inte alltid. Kopiera recepttexten och använd "Klistra in text" istället.</p>
              <button style={{...S.primaryBtn,marginTop:0}} onClick={handleUrlImport} disabled={!url.trim()}>Importera</button>
            </div>
        </>}
        {step==="loading"&&<div style={{padding:"50px 20px",display:"flex",flexDirection:"column",alignItems:"center",gap:24}}>
          <div style={S.spinner}/>
          <p style={{fontSize:13,color:"#1a1a1a"}}>Läser av recept…</p>
          <button onClick={handleAbort} style={{fontSize:13,color:"#1a1a1a",border:"1px solid #E8E4DD",padding:"9px 20px",borderRadius:8,background:"#fff",cursor:"pointer"}}>Avbryt</button>
        </div>}
        {(step==="manual"||step==="edit")&&<>
          <div style={S.modalHead}><button onClick={()=>setStep("menu")} style={S.iconBtn}>←</button><span style={S.eyebrow}>{step==="edit"?"GRANSKA":"NYTT RECEPT"}</span><button onClick={onClose} style={S.iconBtn}>✕</button></div>
          <div style={S.formWrap}>
            {error&&<p style={{color:"#c0392b",fontSize:12,marginBottom:14}}>{error}</p>}
            <div style={S.formGroup}><label style={S.formLabel}>Bild</label>
              <ImagePicker value={draft.customImg} onChange={img=>setDraft(d=>({...d,customImg:img}))} library={library}/>
            </div>
            <div style={S.formGroup}><label style={S.formLabel}>Namn *</label><input style={S.formInput} value={draft.title} onChange={e=>setDraft(d=>({...d,title:e.target.value}))} placeholder="Receptets namn"/></div>
            <div style={S.formGroup}><label style={S.formLabel}>Antal personer</label>
              <div style={{display:"flex",alignItems:"center",gap:16}}><button style={S.servingBtn} onClick={()=>setDraft(d=>({...d,servings:Math.max(1,d.servings-1)}))}>−</button><span style={{fontSize:18,fontWeight:500,minWidth:20,textAlign:"center"}}>{draft.servings}</span><button style={S.servingBtn} onClick={()=>setDraft(d=>({...d,servings:d.servings+1}))}>+</button></div>
            </div>
            <div style={S.formGroup}><label style={S.formLabel}>Kategori {tagsLoading&&<span style={{fontWeight:400,fontSize:12,color:"#1a1a1a",textTransform:"none",letterSpacing:0}}>(föreslår…)</span>}</label><TagEditor tags={draft.tags} onChange={tags=>setDraft(d=>({...d,tags}))}/></div>
            <div style={S.formGroup}><label style={S.formLabel}>Ingredienser <span style={{fontWeight:400,fontSize:12,color:"#1a1a1a",textTransform:"none",letterSpacing:0}}>(en per rad)</span></label><textarea style={{...S.formInput,height:110,resize:"none"}} value={draft.ingredients} onChange={e=>setDraft(d=>({...d,ingredients:e.target.value}))} placeholder={"400g pasta\n150g bacon\n4 ägg"}/></div>
            <div style={S.formGroup}><label style={S.formLabel}>Instruktioner <span style={{fontWeight:400,fontSize:12,color:"#1a1a1a",textTransform:"none",letterSpacing:0}}>(ett steg per rad)</span></label><textarea style={{...S.formInput,height:130,resize:"none"}} value={draft.instructions} onChange={e=>setDraft(d=>({...d,instructions:e.target.value}))} placeholder={"Koka pastan al dente.\nStek baconet..."}/></div>
            <div style={S.formGroup}><label style={S.formLabel}>Källa <span style={{fontWeight:400,fontSize:12,color:"#1a1a1a",textTransform:"none",letterSpacing:0}}>(valfritt)</span></label>
              <input style={{...S.formInput,marginBottom:8}} value={draft.sourceName} onChange={e=>setDraft(d=>({...d,sourceName:e.target.value}))} placeholder="t.ex. Ottolenghi"/>
              <input style={S.formInput} value={draft.sourceUrl} onChange={e=>setDraft(d=>({...d,sourceUrl:e.target.value}))} placeholder="https://..."/>
            </div>
            <div style={S.formGroup}>
              <label style={S.formLabel}>Lägg i samling</label>
              <select style={{...S.formInput,fontSize:16}} value={draft.targetCollection} onChange={e=>setDraft(d=>({...d,targetCollection:e.target.value}))}>
                <option value="">Ingen samling</option>
                <option value="__veckomat__">🗓 Veckomat</option>
                {collections.map(c=><option key={c.id} value={c.id}>{c.emoji} {c.title}</option>)}
              </select>
            </div>
            <button style={S.primaryBtn} onClick={save} disabled={!draft.title.trim()}>Spara recept</button>
          </div>
        </>}
      </div>
    </div>
  );
}

// ── Edit Modal ────────────────────────────────────────────────────────────────
function EditModal({ recipe, onClose, onSave, library }) {
  const [draft, setDraft] = useState({ ...recipe, ingredients:recipe.ingredients?.join("\n")||"", instructions:recipe.instructions?.join("\n")||"", tags:recipe.tags||[], sourceName:recipe.sourceName||"", sourceUrl:recipe.sourceUrl||"" });
  const save = () => { onSave({ ...draft, ingredients:draft.ingredients.split("\n").map(s=>s.trim()).filter(Boolean), instructions:draft.instructions.split("\n").map(s=>s.trim()).filter(Boolean) }); onClose(); };
  return (
    <div style={S.modalBg}>
      <div style={{...S.modalBox,maxHeight:"88vh",overflowY:"auto"}}>
        <div style={S.modalHead}><span style={S.eyebrow}>REDIGERA</span><button onClick={onClose} style={S.iconBtn}>✕</button></div>
        <div style={S.formWrap}>
          <div style={S.formGroup}><label style={S.formLabel}>Bild</label>
            <ImagePicker value={draft.customImg?{src:draft.customImg,name:draft.customImgName||""}:null} onChange={img=>setDraft(d=>({...d,customImg:img?.src||null,customImgName:img?.name||null}))} library={library}/>
          </div>
          <div style={S.formGroup}><label style={S.formLabel}>Namn</label><input style={S.formInput} value={draft.title} onChange={e=>setDraft(d=>({...d,title:e.target.value}))}/></div>
          <div style={S.formGroup}><label style={S.formLabel}>Antal personer</label>
            <div style={{display:"flex",alignItems:"center",gap:16}}><button style={S.servingBtn} onClick={()=>setDraft(d=>({...d,servings:Math.max(1,d.servings-1)}))}>−</button><span style={{fontSize:18,fontWeight:500,minWidth:20,textAlign:"center"}}>{draft.servings}</span><button style={S.servingBtn} onClick={()=>setDraft(d=>({...d,servings:d.servings+1}))}>+</button></div>
          </div>
          <div style={S.formGroup}><label style={S.formLabel}>Kategori</label><TagEditor tags={draft.tags} onChange={tags=>setDraft(d=>({...d,tags}))}/></div>
          <div style={S.formGroup}><label style={S.formLabel}>Ingredienser</label><textarea style={{...S.formInput,height:110,resize:"none"}} value={draft.ingredients} onChange={e=>setDraft(d=>({...d,ingredients:e.target.value}))}/></div>
          <div style={S.formGroup}><label style={S.formLabel}>Instruktioner</label><textarea style={{...S.formInput,height:130,resize:"none"}} value={draft.instructions} onChange={e=>setDraft(d=>({...d,instructions:e.target.value}))}/></div>
          <div style={S.formGroup}><label style={S.formLabel}>Källa</label>
            <input style={{...S.formInput,marginBottom:8}} value={draft.sourceName} onChange={e=>setDraft(d=>({...d,sourceName:e.target.value}))} placeholder="t.ex. Ottolenghi"/>
            <input style={S.formInput} value={draft.sourceUrl} onChange={e=>setDraft(d=>({...d,sourceUrl:e.target.value}))} placeholder="https://..."/>
          </div>
          <button style={S.primaryBtn} onClick={save}>Spara ändringar</button>
        </div>
      </div>
    </div>
  );
}

// ── Replace Modal ─────────────────────────────────────────────────────────────
function ReplaceModal({ day, currentRecipeId, pool, recipes, onClose, onSelect }) {
  const cur = recipes[currentRecipeId]; const curCats = cur?.tags||[];
  const sameCat = pool.filter(r=>r.id!==currentRecipeId&&r.tags?.some(t=>curCats.includes(t)));
  const others = pool.filter(r=>r.id!==currentRecipeId&&!r.tags?.some(t=>curCats.includes(t)));
  return (
    <div style={S.modalBg}>
      <div style={{...S.modalBox,maxHeight:"80vh",overflowY:"auto"}}>
        <div style={S.modalHead}><span style={S.eyebrow}>VÄLJ — {day.toUpperCase()}</span><button onClick={onClose} style={S.iconBtn}>✕</button></div>
        {sameCat.length>0&&<p style={{fontSize:13,letterSpacing:3,color:"#1a1a1a",textTransform:"uppercase",padding:"10px 20px 4px"}}>Samma kategori</p>}
        {[...sameCat,...others].map(r=>(
          <button key={r.id} onClick={()=>{onSelect(day,r.id);onClose();}} style={{display:"flex",alignItems:"center",gap:12,width:"100%",padding:"12px 20px",borderBottom:"1px solid #F7F4EE",textAlign:"left",background:"none",border:"none",cursor:"pointer"}}>
            <FoodImg id={r.id} title={r.title} customImg={r.customImg} style={{width:44,height:44,borderRadius:8,flexShrink:0}} textSize={18}/>
            <div style={{flex:1}}>
              <span style={{fontSize:14,color:"#1a1a1a",display:"block",marginBottom:4,fontWeight:500}}>{r.title}</span>
              <div style={{display:"flex",flexWrap:"wrap",gap:4}}>{r.tags?.map(t=><span key={t} style={S.tagChipSm}>{t}</span>)}</div>
            </div>
          </button>
        ))}
      </div>
    </div>
  );
}

// ── Swipeable Day Row ─────────────────────────────────────────────────────────
function SwipeDayRow({ entry, recipes, isToday, onRecipeClick, onRemove, onShuffle, onReplace, onAdd }) {
  const [offset, setOffset] = useState(0); const [open, setOpen] = useState(false); const startX = useRef(null); const ACTION_W = 180;
  const onTouchStart = e => { startX.current = e.touches[0].clientX; };
  const onTouchMove = e => { if(startX.current===null)return; const dx=e.touches[0].clientX-startX.current; if(dx<0)setOffset(Math.max(dx,-ACTION_W)); };
  const onTouchEnd = () => { if(offset<-60){setOpen(true);setOffset(-ACTION_W);}else{setOpen(false);setOffset(0);} startX.current=null; };
  const close = () => { setOpen(false); setOffset(0); };
  const r = entry.recipe?(recipes[entry.recipe.id]||entry.recipe):null;
  return (
    <div style={{position:"relative",overflow:"hidden",borderBottom:"1px solid #EAE6DF"}}>
      <div style={{position:"absolute",right:0,top:0,bottom:0,width:ACTION_W,display:"flex"}}>
        {[{bg:"#e8f5e8",icon:"⟳",label:"Slumpa",fn:()=>{onShuffle(entry.day);close();}},{bg:"#e8ecf5",icon:"⇄",label:"Byt ut",fn:()=>{onReplace(entry.day);close();}},{bg:"#f5e8e8",icon:"✕",label:"Ta bort",fn:()=>{onRemove(entry.day);close();}}].map(b=>(
          <button key={b.label} onClick={b.fn} style={{flex:1,background:b.bg,border:"none",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4,cursor:"pointer"}}>
            <span style={{fontSize:16}}>{b.icon}</span><span style={{fontSize:13,color:"#333",letterSpacing:1}}>{b.label}</span>
          </button>
        ))}
      </div>
      <div onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}
        onClick={()=>{if(open){close();}else if(r){onRecipeClick(r);}}}
        style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"12px 20px",background:"#fff",cursor:"pointer",transform:`translateX(${offset}px)`,transition:startX.current===null?"transform 0.2s":"none"}}>
        <div style={{display:"flex",alignItems:"center",gap:8,flex:1}}>
          <span style={{fontSize:13,color:"#1a1a1a",fontWeight:isToday?700:400,minWidth:72}}>{entry.day}</span>
          {isToday&&<span style={{fontSize:13,letterSpacing:1,color:"#1a1a1a",textTransform:"uppercase"}}>Idag</span>}
        </div>
        <div style={{display:"flex",alignItems:"center",gap:10,maxWidth:200}}>
          {r?<><span style={{fontSize:12,color:"#444",textAlign:"right",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.title}</span><FoodImg id={r.id} title={r.title} customImg={r.customImg} style={{width:40,height:40,borderRadius:8,flexShrink:0}} textSize={16}/></>
            :<span onClick={e=>{e.stopPropagation();onAdd&&onAdd(entry.day);}} style={{fontSize:26,color:"#ccc",fontWeight:300,padding:"0 4px",cursor:"pointer"}}>+</span>}
        </div>
      </div>
    </div>
  );
}

// ── Shopping Toast ────────────────────────────────────────────────────────────
function ShoppingItem({ text }) {
  const [checked, setChecked] = useState(false);
  return (
    <li onClick={()=>setChecked(c=>!c)} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 16px",borderBottom:"1px solid #F7F4EE",fontSize:13,color:checked?"#ccc":"#555",cursor:"pointer",textDecoration:checked?"line-through":"none"}}>
      <span style={{width:16,height:16,border:`1px solid ${checked?"#ccc":"#ddd"}`,borderRadius:3,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,background:checked?"#eee":"transparent"}}>{checked&&<span style={{color:"#444",fontSize:12}}>✓</span>}</span>
      {text}
    </li>
  );
}
function ShoppingToast({ title, sections, loading, onClose }) {
  return (
    <div style={{position:"fixed",bottom:84,left:14,right:14,maxWidth:440,margin:"0 auto",background:"#fff",border:"1px solid #E8E4DD",borderRadius:16,zIndex:150,maxHeight:"60vh",overflow:"hidden",display:"flex",flexDirection:"column",boxShadow:"0 8px 32px rgba(0,0,0,0.1)"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"13px 16px",borderBottom:"1px solid #F0EDE6",flexShrink:0}}><span style={S.eyebrow}>HANDLARLISTA</span><button onClick={onClose} style={S.iconBtn}>✕</button></div>
      <p style={{fontFamily:"'Libre Baskerville',serif",fontSize:15,padding:"10px 16px 4px",flexShrink:0}}>{title}</p>
      <div style={{overflowY:"auto",flex:1,paddingBottom:16}}>
        {loading&&<div style={{display:"flex",alignItems:"center",gap:10,padding:"20px 16px"}}><div style={S.spinner}/><span style={{fontSize:12,color:"#1a1a1a"}}>Sorterar ingredienser…</span></div>}
        {!loading&&sections?.map((sec,si)=><div key={si}>{sec.heading&&<p style={{fontSize:13,letterSpacing:3,color:"#1a1a1a",textTransform:"uppercase",padding:"14px 16px 4px"}}>{sec.heading}</p>}<ul style={{listStyle:"none"}}>{sec.items.map((ing,i)=><ShoppingItem key={i} text={ing}/>)}</ul></div>)}
      </div>
    </div>
  );
}

// ── Recipe View ───────────────────────────────────────────────────────────────
function RecipeView({ recipe, onBack, onEdit, onSaveComment, collections, onAddToCollection, veckomatPool, onAddToVeckomat }) {
  const [servings, setServings] = useState(recipe.servings||4);
  const [meta, setMeta] = useState(null); const [metaLoading, setMetaLoading] = useState(false);
  const [showShopping, setShowShopping] = useState(false);
  const [tab, setTab] = useState("ingredients");
  const [showAddToCol, setShowAddToCol] = useState(false);
  const [editComment, setEditComment] = useState(false); const [comment, setComment] = useState(recipe.comment||"");
  const scale = servings/(recipe.servings||4);
  const scaleIng = t=>t.replace(/(\d+(?:[,.]\d+)?)/g,m=>{ const s=parseFloat(m)*scale; return s%1===0?s:s.toFixed(1); });
  useEffect(()=>{ if(!meta&&recipe.ingredients?.length){ setMetaLoading(true); getRecipeMeta(recipe).then(m=>{setMeta(m);setMetaLoading(false);}); }}, [recipe.id]);
  const saveComment = () => { onSaveComment(comment); setEditComment(false); };
  return (
    <div>
      <button onClick={onBack} style={S.stickyBack}>←</button>
      <div style={S.view}>
        {showShopping&&<ShoppingToast title={recipe.title} sections={[{heading:null,items:recipe.ingredients?.map(scaleIng)||[]}]} loading={false} onClose={()=>setShowShopping(false)}/>}
        <FoodImg id={recipe.id} title={recipe.title} customImg={recipe.customImg} style={{width:"calc(100% + 40px)",height:240,margin:"-20px -20px 0",borderRadius:0}} textSize={72}/>
        <div style={{display:"flex",justifyContent:"flex-end",marginTop:12}}><button onClick={onEdit} style={{fontSize:12,color:"#1a1a1a",background:"none",border:"none",cursor:"pointer",textDecoration:"underline",textUnderlineOffset:3}}>Redigera</button></div>
        <h1 style={{fontFamily:"'Libre Baskerville',serif",fontSize:26,fontWeight:700,marginTop:12,marginBottom:10,lineHeight:1.2,color:"#1a1a1a"}}>{recipe.title}</h1>
        {recipe.sourceName&&<div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}><span style={{fontSize:13,letterSpacing:3,color:"#1a1a1a",textTransform:"uppercase"}}>Källa</span>{recipe.sourceUrl?<a href={recipe.sourceUrl} target="_blank" rel="noopener noreferrer" style={{fontSize:12,color:"#1a1a1a",textDecoration:"none",borderBottom:"1px solid #EAE6DF"}}>{recipe.sourceName} ↗</a>:<span style={{fontSize:12,color:"#1a1a1a"}}>{recipe.sourceName}</span>}</div>}
        {recipe.tags?.length>0&&<div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:16}}>{recipe.tags.map(t=><span key={t} style={S.tagChipSm}>{t}</span>)}</div>}
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20,paddingBottom:16,borderBottom:"1px solid #F0EDE6"}}>
          <span style={S.formLabel}>Antal personer</span>
          <div style={{display:"flex",alignItems:"center",gap:16}}><button style={S.servingBtn} onClick={()=>setServings(s=>Math.max(1,s-1))}>−</button><span style={{fontSize:18,fontWeight:500,minWidth:20,textAlign:"center"}}>{servings}</span><button style={S.servingBtn} onClick={()=>setServings(s=>s+1)}>+</button></div>
        </div>
        <div style={{display:"flex",gap:0,marginBottom:16,borderBottom:"1px solid #F0EDE6"}}>
          {["ingredients","instructions"].map(t=><button key={t} onClick={()=>setTab(t)} style={{fontSize:12,color:tab===t?"#1a1a1a":"#bbb",padding:"8px 0",marginRight:20,letterSpacing:.5,borderBottom:tab===t?"2px solid #1a1a1a":"2px solid transparent",background:"none",border:"none",cursor:"pointer"}}>{t==="ingredients"?"Ingredienser":"Instruktioner"}</button>)}
        </div>
        {tab==="ingredients"&&<ul style={{listStyle:"none",marginBottom:20}}>{recipe.ingredients?.map((ing,i)=><li key={i} style={{fontSize:14,color:"#1a1a1a",padding:"8px 0",borderBottom:"1px solid #F7F4EE",lineHeight:1.4}}>{scaleIng(ing)}</li>)||<li style={{fontSize:14,color:"#1a1a1a"}}>Inga ingredienser</li>}</ul>}
        {tab==="instructions"&&<ol style={{listStyle:"none",marginBottom:20}}>{recipe.instructions?.map((step,i)=><li key={i} style={{display:"flex",gap:14,padding:"12px 0",borderBottom:"1px solid #F7F4EE",fontSize:14,color:"#1a1a1a",lineHeight:1.6}}><span style={{fontSize:13,color:"#1a1a1a",fontWeight:600,letterSpacing:1,flexShrink:0,paddingTop:2,minWidth:16}}>{i+1}</span><span>{step}</span></li>)||<li style={{fontSize:14,color:"#1a1a1a"}}>Inga instruktioner</li>}</ol>}
        <div style={{marginBottom:24,display:"flex",gap:10,flexWrap:"wrap"}}>
          <button style={{fontSize:13,color:"#333",border:"1px solid #E8E4DD",padding:"9px 16px",borderRadius:8,background:"#fff",cursor:"pointer"}} onClick={()=>setShowShopping(s=>!s)}>🛒 Handlarlista</button>
          <button style={{fontSize:13,color:"#333",border:"1px solid #E8E4DD",padding:"9px 16px",borderRadius:8,background:"#fff",cursor:"pointer"}} onClick={()=>setShowAddToCol(true)}>＋ Lägg i samling</button>
        </div>
        {showAddToCol&&collections&&<PickCollectionModal
          recipe={recipe}
          collections={collections}
          veckomatPool={veckomatPool}
          onClose={()=>setShowAddToCol(false)}
          onPick={colId=>{ onAddToCollection&&onAddToCollection(colId,recipe); }}
          onAddToVeckomat={()=>{ onAddToVeckomat&&onAddToVeckomat(recipe); }}
        />}
        <div style={{paddingTop:20,borderTop:"1px solid #F0EDE6"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}><span style={S.eyebrow}>KOMMENTAR</span>{!editComment&&<button onClick={()=>setEditComment(true)} style={{fontSize:13,color:"#1a1a1a",background:"none",border:"none",cursor:"pointer",textDecoration:"underline",textUnderlineOffset:2}}>{comment?"Redigera":"+ Lägg till"}</button>}</div>
          {editComment?<div><textarea style={{...S.formInput,height:90,resize:"none",marginBottom:10}} value={comment} onChange={e=>setComment(e.target.value)} placeholder="Tankar om rätten, justeringar..."/><div style={{display:"flex",gap:8}}><button style={{flex:1,padding:"8px",border:"1px solid #E8E4DD",borderRadius:8,color:"#1a1a1a",fontSize:12,background:"#fff",cursor:"pointer"}} onClick={()=>{setComment(recipe.comment||"");setEditComment(false);}}>Avbryt</button><button style={{flex:2,padding:"8px",background:"#1a1a1a",borderRadius:8,color:"#F7F4EE",fontSize:12,border:"none",cursor:"pointer"}} onClick={saveComment}>Spara</button></div></div>
            :<p style={{fontSize:13,color:comment?"#666":"#ccc",lineHeight:1.7}}>{comment||"Ingen kommentar ännu"}</p>}
        </div>
        {metaLoading&&<p style={{fontSize:12,color:"#1a1a1a",marginTop:20}}>Hämtar tips…</p>}
        {meta&&<>
          {meta.tips?.length>0&&<div style={S.metaBox}><p style={S.metaTitle}>💡 Tips</p>{meta.tips.map((t,i)=><p key={i} style={{fontSize:13,color:"#1a1a1a",lineHeight:1.6,marginBottom:4}}>· {t}</p>)}</div>}
          {meta.drinks?.length>0&&<div style={S.metaBox}><p style={S.metaTitle}>🍷 Dryck</p>{meta.drinks.map((d,i)=><div key={i} style={{marginBottom:8}}><span style={{fontSize:13,color:"#444",display:"block"}}>{d.name}</span><span style={{fontSize:12,color:"#1a1a1a"}}>{d.why}</span></div>)}</div>}
          {meta.variation&&<div style={S.metaBox}><p style={S.metaTitle}>🔄 Variation</p><p style={{fontSize:13,color:"#1a1a1a",lineHeight:1.6}}>{meta.variation}</p></div>}
        </>}
      </div>
    </div>
  );
}

// ── Week View ─────────────────────────────────────────────────────────────────
function AddToWeekModal({ day, recipes, allRecipes, onClose, onSelect }) {
  const [search, setSearch] = useState("");
  const all = Object.values(allRecipes||{}).filter(r=>r.title).sort((a,b)=>a.title.localeCompare(b.title,"sv"));
  const filtered = search ? all.filter(r=>r.title.toLowerCase().includes(search.toLowerCase())) : all;
  return (
    <div style={S.modalBg}>
      <div style={{...S.modalBox,maxHeight:"85vh",overflowY:"auto"}}>
        <div style={S.modalHead}>
          <span style={S.eyebrow}>VÄLJ RECEPT — {day.toUpperCase()}</span>
          <button onClick={onClose} style={S.iconBtn}>✕</button>
        </div>
        <div style={{padding:"12px 20px"}}>
          <input style={{...S.formInput,fontSize:16}} value={search} onChange={e=>setSearch(e.target.value)} placeholder="Sök recept..."/>
        </div>
        {filtered.map(r=>(
          <button key={r.id} onClick={()=>onSelect(day,r.id)} style={{display:"flex",alignItems:"center",gap:12,width:"100%",padding:"10px 20px",borderBottom:"1px solid #F7F4EE",background:"none",border:"none",cursor:"pointer",textAlign:"left"}}>
            <FoodImg id={r.id} title={r.title} customImg={r.customImg} style={{width:44,height:44,borderRadius:8,flexShrink:0}} textSize={18}/>
            <div>
              <p style={{fontSize:14,color:"#1a1a1a",fontWeight:500,marginBottom:2}}>{r.title}</p>
              <p style={{fontSize:12,color:"#333"}}>{r.tags?.join(", ")}</p>
            </div>
          </button>
        ))}
        {filtered.length===0&&<p style={{fontSize:13,color:"#333",padding:"16px 20px"}}>Inga recept hittades.</p>}
      </div>
    </div>
  );
}

function WeekView({ week, recipes, pool, allRecipes, isNext=false, onBack, onRecipeClick, onUpdateDays, onUpdateComment, onArchive, onActivate }) {
  const [confirm, setConfirm] = useState(false); const [replaceDay, setReplaceDay] = useState(null); const [addDay, setAddDay] = useState(null);
  const [editComment, setEditComment] = useState(false); const [comment, setComment] = useState(week.comment||"");
  const [showShopping, setShowShopping] = useState(false); const [shoppingSections, setShoppingSections] = useState(null); const [shoppingLoading, setShoppingLoading] = useState(false);
  const handleRemove = day => onUpdateDays(week.days.map(e=>e.day===day?{...e,recipe:null}:e));
  const handleShuffle = day => {
    const cur = week.days.find(e=>e.day===day); const curCats=(cur?.recipe?recipes[cur.recipe.id]:null)?.tags||[];
    const sameCat = pool.filter(r=>r.id!==cur?.recipe?.id&&r.tags?.some(t=>curCats.includes(t)));
    const candidates = (sameCat.length>0?sameCat:pool).filter(r=>r.id!==cur?.recipe?.id);
    if(!candidates.length)return;
    const picked=candidates[Math.floor(Math.random()*candidates.length)];
    onUpdateDays(week.days.map(e=>e.day===day?{...e,recipe:{id:picked.id}}:e));
  };
  const handleSelect = (day, id) => onUpdateDays(week.days.map(e=>e.day===day?{...e,recipe:{id}}:e));
  const saveComment = () => { onUpdateComment(comment); setEditComment(false); };
  const allIngredients = week.days.filter(e=>e.recipe&&recipes[e.recipe.id]?.ingredients?.length).flatMap(e=>recipes[e.recipe.id].ingredients);
  const openWeekShopping = async () => {
    setShowShopping(true); if(shoppingSections)return; setShoppingLoading(true);
    const cat = await buildWeekShoppingList(allIngredients);
    setShoppingSections(Object.entries(cat).map(([heading,items])=>({heading,items}))); setShoppingLoading(false);
  };
  return (
    <div>
      <button onClick={onBack} style={S.stickyBack}>←</button>
      {showShopping&&<ShoppingToast title={`Handlarlista ${week.label}`} sections={shoppingLoading?null:(shoppingSections||[])} loading={shoppingLoading} onClose={()=>setShowShopping(false)}/>}
      {replaceDay&&<ReplaceModal day={replaceDay} currentRecipeId={week.days.find(e=>e.day===replaceDay)?.recipe?.id} pool={pool} recipes={recipes} onClose={()=>setReplaceDay(null)} onSelect={handleSelect}/>}
      {addDay&&<AddToWeekModal day={addDay} recipes={recipes} allRecipes={allRecipes} onClose={()=>setAddDay(null)} onSelect={(day,id)=>{handleSelect(day,id);setAddDay(null);}}/>}
      <div style={S.view}>
        <ViewHeader src={ICON_CALENDAR} title={week.label}/>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8,marginTop:8}}>
          <h2 style={{fontFamily:"'Libre Baskerville',serif",fontSize:22,fontWeight:700,color:"#1a1a1a",flex:1}}>{week.label}</h2>
          <span style={{fontSize:13,background:isNext?"#e8f5e8":"#1a1a1a",color:isNext?"#4a8a4a":"#F7F4EE",padding:"3px 10px",borderRadius:10,letterSpacing:1.5,textTransform:"uppercase"}}>{isNext?"Nästa":"Aktiv"}</span>
        </div>
        <p style={{fontSize:13,color:"#1a1a1a",marginBottom:12}}>Svep vänster på en dag för alternativ</p>
        <div style={{borderTop:"1px solid #EAE6DF",margin:"0 -20px"}}>
          {week.days.map((e,i)=><SwipeDayRow key={e.day} entry={e} recipes={recipes} isToday={!isNext&&i===TODAY_IDX} onRecipeClick={onRecipeClick} onRemove={handleRemove} onShuffle={handleShuffle} onReplace={d=>setReplaceDay(d)} onAdd={d=>setAddDay(d)}/>)}
        </div>
        <div style={{marginTop:20,marginBottom:24}}><button style={{fontSize:13,color:"#333",border:"1px solid #E8E4DD",padding:"9px 16px",borderRadius:8,background:"#fff",cursor:"pointer"}} onClick={openWeekShopping} disabled={allIngredients.length===0}>🛒 Handlarlista för veckan</button></div>
        <div style={{paddingTop:20,borderTop:"1px solid #F0EDE6"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}><span style={S.eyebrow}>KOMMENTAR</span>{!editComment&&<button onClick={()=>setEditComment(true)} style={{fontSize:13,color:"#1a1a1a",background:"none",border:"none",cursor:"pointer",textDecoration:"underline",textUnderlineOffset:2}}>{comment?"Redigera":"+ Lägg till"}</button>}</div>
          {editComment?<div><textarea style={{...S.formInput,height:90,resize:"none",marginBottom:10}} value={comment} onChange={e=>setComment(e.target.value)} placeholder="Anteckningar om veckan..."/><div style={{display:"flex",gap:8}}><button style={{flex:1,padding:"8px",border:"1px solid #E8E4DD",borderRadius:8,color:"#1a1a1a",fontSize:12,background:"#fff",cursor:"pointer"}} onClick={()=>{setComment(week.comment||"");setEditComment(false);}}>Avbryt</button><button style={{flex:2,padding:"8px",background:"#1a1a1a",borderRadius:8,color:"#F7F4EE",fontSize:12,border:"none",cursor:"pointer"}} onClick={saveComment}>Spara</button></div></div>
            :<p style={{fontSize:13,color:comment?"#666":"#ccc",lineHeight:1.7}}>{comment||"Ingen kommentar ännu"}</p>}
        </div>
        <button onClick={()=>setConfirm(true)} style={{marginTop:24,fontSize:13,color:"#1a1a1a",background:"none",border:"none",cursor:"pointer",textDecoration:"underline",textUnderlineOffset:2}}>{isNext?"Aktivera som denna vecka":"Arkivera vecka"}</button>
        {confirm&&<div style={S.modalBg}><div style={{...S.modalBox,borderRadius:16,padding:"24px 20px"}}>
          <p style={{fontSize:13,color:"#1a1a1a",lineHeight:1.6,marginBottom:16}}>{isNext?`Aktivera ${week.label}? Den nuvarande veckan arkiveras.`:`Arkivera ${week.label}?`}</p>
          <div style={{display:"flex",gap:8}}>
            <button style={{flex:1,padding:"10px",border:"1px solid #E8E4DD",borderRadius:8,color:"#1a1a1a",fontSize:12,background:"#fff",cursor:"pointer"}} onClick={()=>setConfirm(false)}>Avbryt</button>
            <button style={{flex:1,padding:"10px",background:"#1a1a1a",borderRadius:8,color:"#F7F4EE",fontSize:12,border:"none",cursor:"pointer",fontWeight:600}} onClick={()=>{isNext?onActivate():onArchive();setConfirm(false);}}>{isNext?"Aktivera":"Arkivera"}</button>
          </div>
        </div></div>}
      </div>
    </div>
  );
}

// ── Collection & Recipe cards ─────────────────────────────────────────────────
function ColCard({ col, onClick, editMode, onDelete }) {
  const pid=col.previewId||col.recipes?.[0]?.id; const pt=col.recipes?.[0]?.title||col.title;
  return (
    <div style={{position:"relative"}}>
      <div onClick={()=>!editMode&&onClick(col)}
        style={{position:"relative",height:150,borderRadius:12,overflow:"hidden",cursor:"pointer",
          border:editMode?"2px solid #1a1a1a":"1px solid #EAE6DF",
          transform:editMode?"scale(0.95)":"scale(1)",transition:"transform 0.2s"}}>
        {col.coverImg
          ? <div style={{position:"absolute",inset:0,backgroundImage:`url(${col.coverImg})`,backgroundSize:"contain",backgroundPosition:"center",backgroundRepeat:"no-repeat"}}/>
          : <FoodImg id={pid} title={pt} style={{position:"absolute",inset:0,width:"100%",height:"100%"}} textSize={36}/>}
        <div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(255,255,255,0.97) 0%,rgba(255,255,255,0.1) 60%)",display:"flex",flexDirection:"column",justifyContent:"flex-end",padding:12}}>
          <p style={{fontFamily:"'Libre Baskerville',serif",fontSize:13,color:"#1a1a1a",fontWeight:700,lineHeight:1.2}}>{col.title}</p>
          <p style={{fontSize:12,color:"#333",marginTop:3}}>{(col.recipes?.length||0)+(col.sub?.length||0)} objekt</p>
        </div>
      </div>
      {editMode&&<button onClick={e=>{e.stopPropagation();onDelete(col.id);}} style={{position:"absolute",top:-8,right:-8,width:26,height:26,borderRadius:"50%",background:"#1a1a1a",color:"#fff",border:"2px solid #fff",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",zIndex:10,lineHeight:1}}>×</button>}
    </div>
  );
}
function RecipeCard({ recipe, onClick }) {
  return <div onClick={onClick} style={{cursor:"pointer",minWidth:0}}><FoodImg id={recipe.id} title={recipe.title} customImg={recipe.customImg} style={{width:"100%",height:120,borderRadius:10,border:"1px solid #EAE6DF"}} textSize={28}/><p style={{fontSize:13,color:"#1a1a1a",lineHeight:1.4,marginTop:7,fontWeight:500}}>{recipe.title}</p></div>;
}
function PickCollectionModal({ recipe, collections, veckomatPool, onClose, onPick, onAddToVeckomat }) {
  const flat = (cols) => cols.flatMap(c => [c, ...flat(c.sub||[])]);
  const all = flat(collections);
  const already = new Set(all.filter(c=>(c.recipes||[]).find(r=>r.id===recipe.id)).map(c=>c.id));
  const inVeckomat = veckomatPool?.find(r=>r.id===recipe.id);
  return (
    <div style={S.modalBg}>
      <div style={{...S.modalBox,maxHeight:"80vh",overflowY:"auto"}}>
        <div style={S.modalHead}>
          <span style={S.eyebrow}>LÄGG I SAMLING</span>
          <button onClick={onClose} style={S.iconBtn}>✕</button>
        </div>
        <p style={{fontSize:13,color:"#333",padding:"12px 20px 8px",fontStyle:"italic"}}>{recipe.title}</p>
        {/* Veckomat as first option */}
        <button onClick={()=>{if(!inVeckomat){onAddToVeckomat();onClose();}}}
          style={{display:"flex",alignItems:"center",justifyContent:"space-between",width:"100%",padding:"13px 20px",borderBottom:"1px solid #F7F4EE",background:"none",border:"none",cursor:inVeckomat?"default":"pointer",opacity:inVeckomat?0.4:1}}>
          <span style={{fontSize:14,color:"#1a1a1a",fontWeight:500}}>🗓 Veckomat</span>
          {inVeckomat&&<span style={{fontSize:12,color:"#333"}}>Redan tillagd</span>}
        </button>
        {all.map(col=>(
          <button key={col.id} onClick={()=>{if(!already.has(col.id)){onPick(col.id);onClose();}}}
            style={{display:"flex",alignItems:"center",justifyContent:"space-between",width:"100%",padding:"13px 20px",borderBottom:"1px solid #F7F4EE",background:"none",border:"none",cursor:already.has(col.id)?"default":"pointer",opacity:already.has(col.id)?0.4:1}}>
            <span style={{fontSize:14,color:"#1a1a1a",fontWeight:500}}>{col.emoji||"📁"} {col.title}</span>
            {already.has(col.id)&&<span style={{fontSize:12,color:"#333"}}>Redan tillagd</span>}
          </button>
        ))}
      </div>
    </div>
  );
}

function AddCollectionModal({ onClose, onSave, library }) {
  const [name, setName] = useState("");
  const [coverImg, setCoverImg] = useState(null);
  const [showLibPicker, setShowLibPicker] = useState(false);
  const fileRef = useRef();
  const save = () => {
    if (!name.trim()) return;
    onSave({ id:"c"+Date.now(), title:name.trim(), emoji:"📁", coverImg:coverImg?.src||null, sub:[], recipes:[], previewId:null });
  };
  if (showLibPicker) return (
    <div style={S.modalBg}>
      <div style={{...S.modalBox,maxHeight:"85vh",overflowY:"auto"}}>
        <div style={S.modalHead}>
          <button onClick={()=>setShowLibPicker(false)} style={S.iconBtn}>←</button>
          <span style={S.eyebrow}>VÄLJ BILD</span>
          <button onClick={onClose} style={S.iconBtn}>✕</button>
        </div>
        <div style={{padding:"16px 20px",display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10}}>
          {(library||[]).map(img=>(
            <div key={img.name} onClick={()=>{setCoverImg(img);setShowLibPicker(false);}}
              style={{cursor:"pointer",borderRadius:10,overflow:"hidden",border:coverImg?.name===img.name?"2px solid #1a1a1a":"2px solid transparent",aspectRatio:"1",background:"#F7F4EE",display:"flex",alignItems:"center",justifyContent:"center"}}>
              <img src={img.src} style={{width:"100%",height:"100%",objectFit:"contain",padding:6}} alt={img.name}/>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
  return (
    <div style={S.modalBg}>
      <div style={S.modalBox}>
        <div style={S.modalHead}>
          <span style={S.eyebrow}>NY SAMLING</span>
          <button onClick={onClose} style={S.iconBtn}>✕</button>
        </div>
        <div style={S.formWrap}>
          <div style={S.formGroup}>
            <label style={S.formLabel}>Bild</label>
            {coverImg
              ? <div style={{position:"relative",marginBottom:8}}>
                  <img src={coverImg.src} style={{width:"100%",height:130,objectFit:"contain",borderRadius:10,background:"#F7F4EE",border:"1px solid #EAE6DF"}}/>
                  <button onClick={()=>setCoverImg(null)} style={S.imgRemove}>✕</button>
                </div>
              : null}
            <div style={{display:"flex",gap:8}}>
              <button onClick={()=>fileRef.current.click()} style={{...S.imgUpload,flex:1,padding:"10px 8px",fontSize:12,margin:0}}>📁 Ladda upp</button>
              <button onClick={()=>setShowLibPicker(true)} style={{...S.imgUpload,flex:1,padding:"10px 8px",fontSize:12,margin:0}}>🖼 Bibliotek</button>
            </div>
            <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={e=>{
              const f=e.target.files[0]; if(!f)return;
              const r=new FileReader(); r.onload=ev=>setCoverImg({name:f.name,src:ev.target.result}); r.readAsDataURL(f);
            }}/>
          </div>
          <div style={S.formGroup}>
            <label style={S.formLabel}>Namn</label>
            <input style={{...S.formInput,fontSize:16}} value={name} onChange={e=>setName(e.target.value)} placeholder="Samlingsnamn…" onKeyDown={e=>e.key==="Enter"&&save()}/>
          </div>
          <button style={S.primaryBtn} onClick={save} disabled={!name.trim()}>Skapa samling</button>
        </div>
      </div>
    </div>
  );
}

function AddToCollectionModal({ col, allRecipes, onClose, onAddRecipe, onAddFolder, library }) {
  const [tab, setTab] = useState("recipe");
  const [folderName, setFolderName] = useState("");
  const [coverImg, setCoverImg] = useState(null);
  const [showLibPicker, setShowLibPicker] = useState(false);
  const [search, setSearch] = useState("");
  const fileRef = useRef();
  const existingIds = new Set((col.recipes||[]).map(r=>r.id));
  const available = Object.values(allRecipes).filter(r => r.title && !existingIds.has(r.id));
  const filtered = search ? available.filter(r=>r.title.toLowerCase().includes(search.toLowerCase())) : available;

  if (showLibPicker) return (
    <div style={S.modalBg}>
      <div style={{...S.modalBox,maxHeight:"85vh",overflowY:"auto"}}>
        <div style={S.modalHead}>
          <button onClick={()=>setShowLibPicker(false)} style={S.iconBtn}>←</button>
          <span style={S.eyebrow}>VÄLJ BILD</span>
          <button onClick={onClose} style={S.iconBtn}>✕</button>
        </div>
        <div style={{padding:"16px 20px",display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10}}>
          {(library||[]).map(img=>(
            <div key={img.name} onClick={()=>{setCoverImg(img);setShowLibPicker(false);}}
              style={{cursor:"pointer",borderRadius:10,overflow:"hidden",border:coverImg?.name===img.name?"2px solid #1a1a1a":"2px solid transparent",aspectRatio:"1",background:"#F7F4EE",display:"flex",alignItems:"center",justifyContent:"center"}}>
              <img src={img.src} style={{width:"100%",height:"100%",objectFit:"contain",padding:6}} alt={img.name}/>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  return (
    <div style={S.modalBg}>
      <div style={{...S.modalBox,maxHeight:"85vh",overflowY:"auto"}}>
        <div style={S.modalHead}>
          <span style={S.eyebrow}>LÄGG TILL I {col.title.toUpperCase()}</span>
          <button onClick={onClose} style={S.iconBtn}>✕</button>
        </div>
        <div style={{display:"flex",gap:0,borderBottom:"1px solid #F0EDE6",padding:"0 20px"}}>
          {["recipe","folder"].map(t=>(
            <button key={t} onClick={()=>setTab(t)} style={{fontSize:13,color:tab===t?"#1a1a1a":"#333",padding:"12px 0",marginRight:20,borderBottom:tab===t?"2px solid #1a1a1a":"2px solid transparent",background:"none",border:"none",cursor:"pointer",fontWeight:tab===t?600:400}}>
              {t==="recipe"?"Recept":"Samling"}
            </button>
          ))}
        </div>
        {tab==="recipe"&&<div style={{padding:"16px 20px"}}>
          <input style={{...S.formInput,marginBottom:12,fontSize:16}} value={search} onChange={e=>setSearch(e.target.value)} placeholder="Sök recept…"/>
          {filtered.length===0&&<p style={{fontSize:13,color:"#333",padding:"8px 0"}}>Inga recept hittades.</p>}
          {filtered.map(r=>(
            <button key={r.id} onClick={()=>{onAddRecipe(r);onClose();}} style={{display:"flex",alignItems:"center",gap:12,width:"100%",padding:"10px 0",borderBottom:"1px solid #F7F4EE",background:"none",border:"none",cursor:"pointer",textAlign:"left"}}>
              <FoodImg id={r.id} title={r.title} customImg={r.customImg} style={{width:40,height:40,borderRadius:8,flexShrink:0}} textSize={16}/>
              <div><div style={{fontSize:14,color:"#1a1a1a",fontWeight:500}}>{r.title}</div><div style={{fontSize:12,color:"#333"}}>{r.tags?.join(", ")}</div></div>
            </button>
          ))}
        </div>}
        {tab==="folder"&&<div style={{padding:"16px 20px"}}>
          <div style={S.formGroup}>
            <label style={S.formLabel}>Bild</label>
            {coverImg
              ? <div style={{position:"relative",marginBottom:10}}>
                  <img src={coverImg.src} style={{width:"100%",height:120,objectFit:"contain",borderRadius:10,background:"#F7F4EE",border:"1px solid #EAE6DF"}}/>
                  <button onClick={()=>setCoverImg(null)} style={S.imgRemove}>✕</button>
                </div>
              : null}
            <div style={{display:"flex",gap:8,marginBottom:12}}>
              <button onClick={()=>fileRef.current.click()} style={{...S.imgUpload,flex:1,padding:"10px 8px",fontSize:12,margin:0}}>📁 Ladda upp</button>
              <button onClick={()=>setShowLibPicker(true)} style={{...S.imgUpload,flex:1,padding:"10px 8px",fontSize:12,margin:0}}>🖼 Bibliotek</button>
            </div>
            <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={e=>{
              const f=e.target.files[0]; if(!f)return;
              const r=new FileReader(); r.onload=ev=>setCoverImg({name:f.name,src:ev.target.result}); r.readAsDataURL(f);
            }}/>
          </div>
          <div style={S.formGroup}>
            <label style={S.formLabel}>Namn</label>
            <input style={{...S.formInput,fontSize:16}} value={folderName} onChange={e=>setFolderName(e.target.value)} placeholder="Samlingsnamn…"/>
          </div>
          <button style={S.primaryBtn} disabled={!folderName.trim()} onClick={()=>{
            onAddFolder({id:"c"+Date.now(),title:folderName.trim(),emoji:"📁",coverImg:coverImg?.src||null,sub:[],recipes:[]});
            onClose();
          }}>Skapa samling</button>
        </div>}
      </div>
    </div>
  );
}

function MoveRecipeModal({ recipe, collections, currentColId, onClose, onMove }) {
  const flat = (cols) => cols.flatMap(c => [c, ...flat(c.sub||[])]);
  const all = flat(collections).filter(c => c.id !== currentColId);
  return (
    <div style={S.modalBg}>
      <div style={{...S.modalBox,maxHeight:"75vh",overflowY:"auto"}}>
        <div style={S.modalHead}>
          <span style={S.eyebrow}>FLYTTA TILL</span>
          <button onClick={onClose} style={S.iconBtn}>✕</button>
        </div>
        <p style={{fontSize:13,color:"#333",padding:"10px 20px 4px",fontStyle:"italic"}}>{recipe.title}</p>
        {all.map(col=>(
          <button key={col.id} onClick={()=>{onMove(col.id);onClose();}}
            style={{display:"flex",alignItems:"center",gap:12,width:"100%",padding:"13px 20px",borderBottom:"1px solid #F7F4EE",background:"none",border:"none",cursor:"pointer",textAlign:"left"}}>
            <span style={{fontSize:14,color:"#1a1a1a",fontWeight:500}}>{col.emoji||"📁"} {col.title}</span>
          </button>
        ))}
      </div>
    </div>
  );
}

function EditCollectionModal({ col, library, onClose, onSave }) {
  const [name, setName] = useState(col.title||"");
  const [coverImg, setCoverImg] = useState(col.coverImg ? {src:col.coverImg,name:col.title} : null);
  const [showLibPicker, setShowLibPicker] = useState(false);
  const fileRef = useRef();
  if (showLibPicker) return (
    <div style={S.modalBg}>
      <div style={{...S.modalBox,maxHeight:"85vh",overflowY:"auto"}}>
        <div style={S.modalHead}>
          <button onClick={()=>setShowLibPicker(false)} style={S.iconBtn}>←</button>
          <span style={S.eyebrow}>VÄLJ BILD</span>
          <button onClick={onClose} style={S.iconBtn}>✕</button>
        </div>
        <div style={{padding:"16px 20px",display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10}}>
          {(library||[]).map(img=>(
            <div key={img.name} onClick={()=>{setCoverImg(img);setShowLibPicker(false);}}
              style={{cursor:"pointer",borderRadius:10,overflow:"hidden",border:coverImg?.name===img.name?"2px solid #1a1a1a":"2px solid transparent",aspectRatio:"1",background:"#F7F4EE",display:"flex",alignItems:"center",justifyContent:"center"}}>
              <img src={img.src} style={{width:"100%",height:"100%",objectFit:"contain",padding:6}} alt={img.name}/>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
  return (
    <div style={S.modalBg}>
      <div style={S.modalBox}>
        <div style={S.modalHead}>
          <span style={S.eyebrow}>REDIGERA SAMLING</span>
          <button onClick={onClose} style={S.iconBtn}>✕</button>
        </div>
        <div style={S.formWrap}>
          <div style={S.formGroup}>
            <label style={S.formLabel}>Bild</label>
            {coverImg?.src && <div style={{position:"relative",marginBottom:10}}>
              <img src={coverImg.src} style={{width:"100%",height:130,objectFit:"contain",borderRadius:10,background:"#F7F4EE",border:"1px solid #EAE6DF"}}/>
              <button onClick={()=>setCoverImg(null)} style={S.imgRemove}>✕</button>
            </div>}
            <div style={{display:"flex",gap:8}}>
              <button onClick={()=>fileRef.current.click()} style={{...S.imgUpload,flex:1,padding:"10px 8px",fontSize:12,margin:0}}>📁 Ladda upp</button>
              <button onClick={()=>setShowLibPicker(true)} style={{...S.imgUpload,flex:1,padding:"10px 8px",fontSize:12,margin:0}}>🖼 Bibliotek</button>
            </div>
            <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={e=>{
              const f=e.target.files[0]; if(!f)return;
              const r=new FileReader(); r.onload=ev=>setCoverImg({name:f.name,src:ev.target.result}); r.readAsDataURL(f);
            }}/>
          </div>
          <div style={S.formGroup}>
            <label style={S.formLabel}>Namn</label>
            <input style={{...S.formInput,fontSize:16}} value={name} onChange={e=>setName(e.target.value)}/>
          </div>
          <button style={S.primaryBtn} onClick={()=>onSave({...col,title:name.trim()||col.title,coverImg:coverImg?.src||null})}>Spara</button>
        </div>
      </div>
    </div>
  );
}

function ColView({ col, onBack, onRecipeClick, onSubClick, allRecipes, onAddRecipe, onAddFolder, onRemoveRecipe, onMoveRecipe, collections, library, onEditCollection }) {
  const [showAdd, setShowAdd] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [movingRecipe, setMovingRecipe] = useState(null);
  const [showEditCol, setShowEditCol] = useState(false);
  const [showShopping, setShowShopping] = useState(false);
  const [shoppingSections, setShoppingSections] = useState(null);
  const [shoppingLoading, setShoppingLoading] = useState(false);

  // Collect all ingredients from this collection recursively
  const collectIngredients = (c) => {
    const fromRecipes = (c.recipes||[]).flatMap(r => (allRecipes[r.id]||r).ingredients||[]);
    const fromSubs = (c.sub||[]).flatMap(s => collectIngredients(s));
    return [...fromRecipes, ...fromSubs];
  };

  const openShopping = async () => {
    setShowShopping(true);
    if (shoppingSections) return;
    setShoppingLoading(true);
    const ings = collectIngredients(col);
    if (!ings.length) { setShoppingSections([]); setShoppingLoading(false); return; }
    const cat = await buildWeekShoppingList(ings);
    setShoppingSections(Object.entries(cat).map(([heading,items])=>({heading,items})));
    setShoppingLoading(false);
  };

  return (
    <div>
      <button onClick={onBack} style={S.stickyBack}>←</button>
      {showShopping&&<ShoppingToast title={col.title} sections={shoppingLoading?null:(shoppingSections||[])} loading={shoppingLoading} onClose={()=>setShowShopping(false)}/>}
      {col.coverImg && (
        <div style={{position:"relative",height:200,overflow:"hidden"}}>
          <div style={{position:"absolute",inset:0,backgroundImage:`url(${col.coverImg})`,backgroundSize:"contain",backgroundPosition:"center",backgroundRepeat:"no-repeat",background:col.coverImg?`#F7F4EE url(${col.coverImg}) center/contain no-repeat`:"#F7F4EE"}}/>
          <div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(247,244,238,1) 0%,rgba(247,244,238,0) 60%)"}}/>
        </div>
      )}
      <div style={S.view}>
        {!col.coverImg&&<div style={{height:20}}/>}
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:24,marginTop:col.coverImg?-20:0,flexWrap:"wrap"}}>
          <h2 style={{fontFamily:"'Libre Baskerville',serif",fontSize:22,fontWeight:700,color:"#1a1a1a",margin:0,flex:1}}>{col.title}</h2>
          {editMode
            ? <button onClick={()=>setEditMode(false)} style={{background:"#1a1a1a",color:"#F7F4EE",border:"none",borderRadius:8,padding:"7px 14px",fontSize:13,cursor:"pointer",fontWeight:600}}>Klar</button>
            : <div style={{display:"flex",gap:8,flexWrap:"wrap",justifyContent:"flex-end"}}>
                <button onClick={openShopping} style={{background:"#fff",color:"#1a1a1a",border:"1px solid #E8E4DD",borderRadius:8,padding:"7px 10px",fontSize:13,cursor:"pointer"}}>🛒</button>
                <button onClick={()=>setShowEditCol(true)} style={{background:"#fff",color:"#1a1a1a",border:"1px solid #E8E4DD",borderRadius:8,padding:"7px 10px",fontSize:13,cursor:"pointer"}}>✏️</button>
                <button onClick={()=>setEditMode(true)} style={{background:"#fff",color:"#1a1a1a",border:"1px solid #E8E4DD",borderRadius:8,padding:"7px 14px",fontSize:13,cursor:"pointer"}}>Redigera</button>
                <button onClick={()=>setShowAdd(true)} style={{background:"#1a1a1a",color:"#F7F4EE",border:"none",borderRadius:8,padding:"7px 14px",fontSize:13,cursor:"pointer",fontWeight:500}}>+ Lägg till</button>
              </div>}
        </div>

        {col.sub?.length>0&&<section style={{marginBottom:28}}>
          <span style={S.eyebrow}>SAMLINGAR</span>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginTop:12}}>
            {col.sub.map(s=>(
              <div key={s.id} style={{position:"relative"}}>
                <ColCard col={s} onClick={onSubClick} editMode={editMode} onDelete={()=>onRemoveRecipe&&onRemoveRecipe(null,s.id,"sub")}/>
              </div>
            ))}
          </div>
        </section>}

        {col.recipes?.length>0&&<section style={{marginBottom:28}}>
          <span style={S.eyebrow}>RECEPT</span>
          {editMode
            ? <div style={{marginTop:12}}>
                {col.recipes.map(r=>{
                  const full = allRecipes[r.id]||r;
                  return (
                    <div key={r.id} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 0",borderBottom:"1px solid #EAE6DF"}}>
                      <FoodImg id={full.id} title={full.title} customImg={full.customImg} style={{width:48,height:48,borderRadius:8,border:"1px solid #EAE6DF",flexShrink:0}} textSize={18}/>
                      <p style={{flex:1,fontSize:14,color:"#1a1a1a",fontWeight:500}}>{full.title}</p>
                      <button onClick={()=>setMovingRecipe(full)} style={{fontSize:12,color:"#1a1a1a",border:"1px solid #E8E4DD",borderRadius:6,padding:"8px 10px",background:"#fff",cursor:"pointer",flexShrink:0}}>Flytta</button>
                      <button onClick={()=>onRemoveRecipe&&onRemoveRecipe(r.id,null,"recipe")} style={{fontSize:12,color:"#c0392b",border:"1px solid #fdd",borderRadius:6,padding:"8px 10px",background:"#fff",cursor:"pointer",flexShrink:0}}>Ta bort</button>
                    </div>
                  );
                })}
              </div>
            : <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginTop:12}}>
                {col.recipes.map(r=>{
                  const full = allRecipes[r.id]||r;
                  return (
                    <div key={r.id} onClick={()=>onRecipeClick(full)} style={{cursor:"pointer",minWidth:0}}>
                      <FoodImg id={full.id} title={full.title} customImg={full.customImg} style={{width:"100%",height:120,borderRadius:10,border:"1px solid #EAE6DF"}} textSize={28}/>
                      <p style={{fontSize:13,color:"#1a1a1a",lineHeight:1.4,marginTop:7,fontWeight:500}}>{full.title}</p>
                    </div>
                  );
                })}
              </div>}
        </section>}

        {!col.sub?.length&&!col.recipes?.length&&<p style={{fontSize:13,color:"#1a1a1a",padding:"20px 0"}}>Inga recept ännu — tryck + Lägg till!</p>}
        {showAdd&&<AddToCollectionModal col={col} allRecipes={allRecipes} library={library} onClose={()=>setShowAdd(false)} onAddRecipe={onAddRecipe} onAddFolder={onAddFolder}/>}
        {showEditCol&&<EditCollectionModal col={col} library={library} onClose={()=>setShowEditCol(false)} onSave={updated=>{onEditCollection&&onEditCollection(updated);setShowEditCol(false);}}/>}
        {movingRecipe&&<MoveRecipeModal recipe={movingRecipe} collections={collections||[]} currentColId={col.id} onClose={()=>setMovingRecipe(null)} onMove={targetColId=>onMoveRecipe&&onMoveRecipe(movingRecipe.id,col.id,targetColId)}/>}
      </div>
    </div>
  );
}



function Hero({ entry, recipes, weekLabel, onWeekClick, onRecipeClick }) {
  if (!entry?.recipe) return (
    <div style={{height:160,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:12,borderBottom:"1px solid #EAE6DF",background:"#fff"}}>
      <p style={{fontSize:14,color:"#1a1a1a"}}>Ingen rätt planerad idag</p>
      <button onClick={onWeekClick} style={{fontSize:13,color:"#1a1a1a",background:"none",border:"none",cursor:"pointer",textDecoration:"underline",textUnderlineOffset:3}}>Planera veckan →</button>
    </div>
  );
  const r = recipes[entry.recipe.id]||entry.recipe;
  return (
    <div style={{position:"relative",height:380,cursor:"pointer",overflow:"hidden"}} onClick={()=>onRecipeClick(r)}>
      <FoodImg id={r.id} title={r.title} customImg={r.customImg} style={{position:"absolute",inset:0,width:"100%",height:"100%"}} textSize={80}/>
      <div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(247,244,238,1) 0%,rgba(247,244,238,0.2) 55%,transparent 100%)"}}/>
      <div style={{position:"absolute",bottom:0,left:0,right:0,padding:"24px 20px"}}>
        <button onClick={e=>{e.stopPropagation();onWeekClick();}} style={{fontSize:12,color:"#1a1a1a",letterSpacing:2,textTransform:"uppercase",marginBottom:8,display:"block",background:"none",border:"none",cursor:"pointer",padding:0}}>{weekLabel} →</button>
        <p style={{fontSize:13,color:"#1a1a1a",letterSpacing:4,textTransform:"uppercase",marginBottom:5}}>DAGENS RÄTT</p>
        <h1 style={{fontFamily:"'Libre Baskerville',serif",fontSize:26,fontWeight:700,lineHeight:1.2,color:"#1a1a1a"}}>{r.title}</h1>
      </div>
    </div>
  );
}
function WeekStrip({ week, recipes, onWeekClick, onRecipeClick }) {
  return (
    <section style={{padding:"20px 20px 0"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",marginBottom:14}}><span style={S.eyebrow}>{week.label}</span><button onClick={onWeekClick} style={{fontSize:13,color:"#1a1a1a",background:"none",border:"none",cursor:"pointer"}}>Se alla →</button></div>
      <div style={{display:"flex",gap:10,overflowX:"auto",paddingBottom:4}}>
        {week.days.map((entry,i)=>{
          const r=entry.recipe?(recipes[entry.recipe.id]||entry.recipe):null;
          return (
            <div key={entry.day} onClick={()=>r&&onRecipeClick(r)} style={{flexShrink:0,width:80,cursor:r?"pointer":"default"}}>
              <p style={{fontSize:13,letterSpacing:3,color:"#1a1a1a",marginBottom:6,textTransform:"uppercase"}}>{entry.day.slice(0,3).toUpperCase()}</p>
              {r?<FoodImg id={r.id} title={r.title} customImg={r.customImg} style={{width:80,height:80,borderRadius:10,border:"1px solid #EAE6DF"}} textSize={22}/>:<div style={{width:80,height:80,background:"#F0EDE6",borderRadius:10,border:"1px solid #EAE6DF"}}/>}
              <p style={{fontSize:12,color:"#1a1a1a",lineHeight:1.3,height:26,overflow:"hidden",marginTop:6}}>{r?.title||"—"}</p>
            </div>
          );
        })}
      </div>
    </section>
  );
}

// ── AI Assistant ──────────────────────────────────────────────────────────────
function AIAssistant({ context, pool, week, recipes }) {
  const [open, setOpen] = useState(false); const [msgs, setMsgs] = useState([]); const [input, setInput] = useState(""); const [loading, setLoading] = useState(false); const bottomRef = useRef(null);
  const send = async () => {
    if(!input.trim()||loading)return;
    const userMsg={role:"user",content:input.trim()}; const next=[...msgs,userMsg];
    setMsgs(next); setInput(""); setLoading(true);
    const system=`Du är en vänlig matassistent i en personlig receptapp. Svara kort, max 3-4 meningar. Kontext: ${JSON.stringify({...context,poolSize:pool?.length,weekDays:week?.days?.map(d=>({day:d.day,recipe:d.recipe?recipes[d.recipe.id]?.title:null}))})}`;
    try {
      const reply=await askAI(next,system);
      setMsgs([...next,{role:"assistant",content:reply||"Inget svar — kontrollera att appen är deployad på Netlify."}]);
    } catch(e) {
      setMsgs([...next,{role:"assistant",content:"Fel: "+e.message}]);
    }
    setLoading(false);
    setTimeout(()=>bottomRef.current?.scrollIntoView({behavior:"smooth"}),50);
  };
  return (
    <>
      {open&&<div onClick={()=>setOpen(false)} style={{position:"fixed",inset:0,zIndex:98}}/>}
      {open&&<div style={{position:"fixed",bottom:84,right:14,left:14,maxWidth:440,margin:"0 auto",background:"#fff",border:"1px solid #E8E4DD",borderRadius:16,zIndex:99,display:"flex",flexDirection:"column",maxHeight:"52vh",boxShadow:"0 8px 32px rgba(0,0,0,0.1)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"13px 16px",borderBottom:"1px solid #F0EDE6"}}><span style={S.eyebrow}>ASSISTENT</span><button onClick={()=>setOpen(false)} style={S.iconBtn}>✕</button></div>
        <div style={{flex:1,overflowY:"auto",padding:"14px 16px",display:"flex",flexDirection:"column",gap:10}}>
          {msgs.length===0&&<p style={{fontSize:12,color:"#1a1a1a",lineHeight:1.7}}>Fråga mig vad du kan laga av resterna, vilken dessert som passar, eller hur du justerar en rätt.</p>}
          {msgs.map((m,i)=><div key={i} style={{fontSize:13,lineHeight:1.6,padding:"9px 12px",borderRadius:10,maxWidth:"90%",background:m.role==="user"?"#F0EDE6":"#F7F4EE",color:"#1a1a1a",alignSelf:m.role==="user"?"flex-end":"flex-start"}}>{m.content}</div>)}
          {loading&&<div style={{fontSize:13,padding:"9px 12px",borderRadius:10,background:"#F7F4EE",color:"#1a1a1a",alignSelf:"flex-start"}}>…</div>}
          <div ref={bottomRef}/>
        </div>
        <div style={{display:"flex",gap:8,padding:"12px 14px",borderTop:"1px solid #F0EDE6"}}>
          <input style={{...S.formInput,flex:1,padding:"9px 12px",fontSize:16}} value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&send()} placeholder="Skriv här…"/>
          <button onClick={send} style={{background:"#1a1a1a",color:"#F7F4EE",borderRadius:8,padding:"0 14px",fontSize:16,fontWeight:700,border:"none",cursor:"pointer"}} disabled={loading}>↑</button>
        </div>
      </div>}
      <button onClick={()=>setOpen(o=>!o)} style={{position:"fixed",bottom:24,right:20,width:50,height:50,borderRadius:"50%",background:"#1a1a1a",color:"#F7F4EE",fontSize:18,display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 4px 24px rgba(0,0,0,0.12)",zIndex:100,border:"none",cursor:"pointer"}}>✦</button>
    </>
  );
}

// ── App ───────────────────────────────────────────────────────────────────────
export default function App() {
  const [data, setData] = useState(()=>{
    const saved = loadData();
    if (!saved) return SEED;
    // Migrate images from SEED into saved recipes that are missing them
    const allSeedRecipes = { ...SEED_RECIPES, ...Object.fromEntries(VECKOMAT_POOL.map(r=>[r.id,r])) };
    Object.keys(allSeedRecipes).forEach(id => {
      if (saved.recipes[id] && !saved.recipes[id].customImg && allSeedRecipes[id].customImg) {
        saved.recipes[id].customImg = allSeedRecipes[id].customImg;
        saved.recipes[id].customImgName = allSeedRecipes[id].customImgName;
      }
    });
    // Migrate coverImg into saved collections that are missing them
    const migrateCols = (savedCols, seedCols) => {
      if (!savedCols || !seedCols) return;
      savedCols.forEach(sc => {
        const seed = seedCols.find(s=>s.id===sc.id);
        if (seed && !sc.coverImg && seed.coverImg) sc.coverImg = seed.coverImg;
        migrateCols(sc.sub, seed?.sub);
      });
    };
    migrateCols(saved.collections, SEED.collections);
    return saved;
  });
  const [library, setLibrary] = useState(()=>loadLibrary());
  const [stack, setStack] = useState([]);
  const [showImport, setShowImport] = useState(false);
  const [showAddCollection, setShowAddCollection] = useState(false);
  const [collectionEditMode, setCollectionEditMode] = useState(false);
  const [editingRecipe, setEditingRecipe] = useState(null);
  useEffect(()=>{ saveData(data); },[data]);
  useEffect(()=>{ saveLibrary(library); },[library]);
  const handleLibraryChange = (lib) => { setLibrary(lib); };
  const push = s=>setStack(p=>[...p,s]); const pop=()=>setStack(p=>p.slice(0,-1)); const cur=stack[stack.length-1];
  const openRecipe = r=>push({type:"recipe",payload:data.recipes[r.id]||r});
  const handleImported = (recipe, targetCollection) => {
    setData(d=>{
      let nd = {...d, recipes:{...d.recipes,[recipe.id]:recipe}};
      if(targetCollection==="__veckomat__") {
        if(!nd.veckomatPool.find(r=>r.id===recipe.id))
          nd = {...nd, veckomatPool:[...nd.veckomatPool, recipe]};
      } else if(targetCollection) {
        const addToCol = (cols) => cols.map(c => {
          if(c.id===targetCollection) return {...c, recipes:[...(c.recipes||[]), {id:recipe.id,title:recipe.title}]};
          if(c.sub) return {...c, sub:addToCol(c.sub)};
          return c;
        });
        nd = {...nd, collections:addToCol(nd.collections)};
      }
      return nd;
    });
    push({type:"recipe",payload:recipe});
  };
  const handleSaveEdit = updated=>{ setData(d=>({...d,recipes:{...d.recipes,[updated.id]:updated}})); setStack(p=>p.map(s=>s.type==="recipe"&&s.payload.id===updated.id?{...s,payload:updated}:s)); setEditingRecipe(null); };
  const handleRemoveFromPool = id=>setData(d=>({...d,veckomatPool:d.veckomatPool.filter(r=>r.id!==id)}));
  const handleUpdateDays = days=>setData(d=>({...d,activeWeek:{...d.activeWeek,days}}));
  const handleUpdateNextDays = days=>setData(d=>({...d,nextWeek:{...d.nextWeek,days}}));
  const handleUpdateComment = comment=>setData(d=>({...d,activeWeek:{...d.activeWeek,comment}}));
  const handleUpdateNextComment = comment=>setData(d=>({...d,nextWeek:{...d.nextWeek,comment}}));
  const handleArchive = () => {
    const nextDays=data.nextWeek.days; const usedIds=new Set(nextDays.filter(d=>d.recipe).map(d=>d.recipe.id));
    const available=data.veckomatPool.filter(r=>!usedIds.has(r.id)); const emptyCats=[...REQUIRED_CATS];
    const filled=nextDays.map(entry=>{
      if(entry.recipe)return entry;
      const catIdx=emptyCats.findIndex(cat=>available.some(r=>r.tags?.includes(cat)&&!usedIds.has(r.id))); let pick;
      if(catIdx>=0){const cat=emptyCats.splice(catIdx,1)[0];const c=available.filter(r=>r.tags?.includes(cat)&&!usedIds.has(r.id));pick=c[Math.floor(Math.random()*c.length)];}
      else{const c=available.filter(r=>!usedIds.has(r.id));pick=c[Math.floor(Math.random()*c.length)];}
      if(pick){usedIds.add(pick.id);return{...entry,recipe:{id:pick.id}};}
      return entry;
    });
    setData(d=>({...d,archivedWeeks:[...d.archivedWeeks,d.activeWeek],activeWeek:{...d.nextWeek,days:filled,id:`w${WEEK_NUM}`,label:`Vecka ${WEEK_NUM}`},nextWeek:{id:`w${WEEK_NUM+1}`,label:`Vecka ${WEEK_NUM+1}`,comment:"",days:DAYS.map(day=>({day,recipe:null}))}}));
    pop();
  };
  const aiCtx={screen:cur?.type||"home",activeWeek:data.activeWeek.label,todayRecipe:data.activeWeek.days[TODAY_IDX]?.recipe?.id?(data.recipes[data.activeWeek.days[TODAY_IDX].recipe.id]?.title||null):null};
  const render = () => {
    if(!cur) return (
      <div>
        <Hero entry={data.activeWeek.days[TODAY_IDX]} recipes={data.recipes} weekLabel={data.activeWeek.label} onWeekClick={()=>push({type:"week"})} onRecipeClick={openRecipe}/>
        <WeekStrip week={data.activeWeek} recipes={data.recipes} onWeekClick={()=>push({type:"week"})} onRecipeClick={openRecipe}/>
        <section style={{padding:"24px 20px"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:0}}>
            <span style={S.eyebrow}>SAMLINGAR</span>
            {collectionEditMode
              ? <button onClick={()=>setCollectionEditMode(false)} style={{fontSize:13,color:"#fff",border:"none",padding:"5px 14px",borderRadius:8,background:"#1a1a1a",cursor:"pointer",fontWeight:600}}>Klar</button>
              : <div style={{display:"flex",gap:8}}>
                  <button onClick={()=>setCollectionEditMode(true)} style={{fontSize:13,color:"#1a1a1a",border:"1px solid #E8E4DD",padding:"5px 12px",borderRadius:8,background:"#fff",cursor:"pointer"}}>Redigera</button>
                  <button onClick={()=>setShowAddCollection(true)} style={{fontSize:13,color:"#1a1a1a",border:"1px solid #E8E4DD",padding:"5px 12px",borderRadius:8,background:"#fff",cursor:"pointer",fontWeight:500}}>+ Samling</button>
                </div>}
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginTop:14}}>
            <div onClick={()=>push({type:"nextweek"})} style={{height:150,borderRadius:12,overflow:"hidden",cursor:"pointer",border:"1px solid #EAE6DF",position:"relative"}}><div style={{position:"absolute",inset:0,backgroundImage:`url(data:image/jpeg;base64,)`,backgroundSize:"contain",backgroundPosition:"center",backgroundRepeat:"no-repeat",opacity:1}}/><div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(255,255,255,0.97) 0%,rgba(255,255,255,0.1) 60%)",display:"flex",flexDirection:"column",justifyContent:"flex-end",padding:12}}><p style={{fontFamily:"'Libre Baskerville',serif",fontSize:13,color:"#1a1a1a",fontWeight:700}}>Nästa vecka</p><p style={{fontSize:12,color:"#333",marginTop:3}}>{data.nextWeek.days.filter(d=>d.recipe).length} av 7 planerade</p></div></div>
            <div onClick={()=>push({type:"veckomat"})} style={{height:150,borderRadius:12,overflow:"hidden",cursor:"pointer",border:"1px solid #EAE6DF",position:"relative"}}><div style={{position:"absolute",inset:0,backgroundImage:`url(data:image/jpeg;base64,)`,backgroundSize:"contain",backgroundPosition:"center",backgroundRepeat:"no-repeat"}}/><div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(255,255,255,0.97) 0%,rgba(255,255,255,0.1) 60%)",display:"flex",flexDirection:"column",justifyContent:"flex-end",padding:12}}><p style={{fontFamily:"'Libre Baskerville',serif",fontSize:13,color:"#1a1a1a",fontWeight:700}}>Veckomat</p><p style={{fontSize:12,color:"#333",marginTop:3}}>{data.veckomatPool.length} recept i poolen</p></div></div>
            <div onClick={()=>push({type:"allrecipes"})} style={{height:150,borderRadius:12,overflow:"hidden",cursor:"pointer",border:"1px solid #EAE6DF",position:"relative"}}>
              <div style={{position:"absolute",inset:0,backgroundImage:`url(${ICON_GLOBE})`,backgroundSize:"contain",backgroundPosition:"center",backgroundRepeat:"no-repeat"}}/>
              <div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(255,255,255,0.97) 0%,rgba(255,255,255,0.1) 60%)",display:"flex",flexDirection:"column",justifyContent:"flex-end",padding:12}}>
                <p style={{fontFamily:"'Libre Baskerville',serif",fontSize:13,color:"#1a1a1a",fontWeight:700}}>Alla recept</p>
                <p style={{fontSize:12,color:"#333",marginTop:3}}>{Object.values(data.recipes).filter(r=>r.title).length} recept</p>
              </div>
            </div>
            <div onClick={()=>push({type:"imglib"})} style={{height:150,borderRadius:12,overflow:"hidden",cursor:"pointer",border:"1px solid #EAE6DF",position:"relative"}}><div style={{position:"absolute",inset:0,backgroundImage:`url(data:image/jpeg;base64,)`,backgroundSize:"contain",backgroundPosition:"center",backgroundRepeat:"no-repeat",opacity:1}}/><div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(255,255,255,0.97) 0%,rgba(255,255,255,0.1) 60%)",display:"flex",flexDirection:"column",justifyContent:"flex-end",padding:12}}><p style={{fontFamily:"'Libre Baskerville',serif",fontSize:13,color:"#1a1a1a",fontWeight:700}}>Bildbibliotek</p><p style={{fontSize:12,color:"#333",marginTop:3}}>{library.length} bilder</p></div></div>
            {data.collections.map((c,i)=>(
              <ColCard key={c.id} col={c}
                editMode={collectionEditMode}
                onClick={c=>push({type:"col",payload:c})}
                onDelete={id=>{
                  setData(d=>({...d,collections:d.collections.filter(col=>col.id!==id)}));
                }}
              />
            ))}
          </div>
        </section>
      </div>
    );
    if(cur.type==="week") return <WeekView week={data.activeWeek} recipes={data.recipes} pool={data.veckomatPool} allRecipes={data.recipes} onBack={pop} onRecipeClick={openRecipe} onUpdateDays={handleUpdateDays} onUpdateComment={handleUpdateComment} onArchive={handleArchive}/>;
    if(cur.type==="nextweek") return <WeekView week={data.nextWeek} recipes={data.recipes} pool={data.veckomatPool} allRecipes={data.recipes} isNext={true} onBack={pop} onRecipeClick={openRecipe} onUpdateDays={handleUpdateNextDays} onUpdateComment={handleUpdateNextComment} onArchive={handleArchive} onActivate={handleArchive}/>;
    if(cur.type==="col") return <ColView
      col={cur.payload}
      onBack={pop}
      onRecipeClick={openRecipe}
      onSubClick={c=>push({type:"col",payload:c})}
      allRecipes={data.recipes}
      onAddRecipe={recipe=>{
        // Add recipe ref to collection
        setData(d=>{
          const addToCol = (cols, targetId, recipe) => cols.map(c => {
            if (c.id===targetId) return {...c, recipes:[...(c.recipes||[]), {id:recipe.id,title:recipe.title}]};
            if (c.sub) return {...c, sub:addToCol(c.sub, targetId, recipe)};
            return c;
          });
          return {...d, collections:addToCol(d.collections, cur.payload.id, recipe)};
        });
        setStack(p=>p.map(s=>{
          if(s.type!=="col") return s;
          const updateCol = (c) => {
            if(c.id===cur.payload.id) return {...c, recipes:[...(c.recipes||[]), {id:recipe.id,title:recipe.title}]};
            if(c.sub) return {...c, sub:c.sub.map(updateCol)};
            return c;
          };
          return {...s, payload:updateCol(s.payload)};
        }));
      }}
      onAddFolder={folder=>{
        setData(d=>{
          const addFolder = (cols, targetId, folder) => cols.map(c => {
            if (c.id===targetId) return {...c, sub:[...(c.sub||[]), folder]};
            if (c.sub) return {...c, sub:addFolder(c.sub, targetId, folder)};
            return c;
          });
          return {...d, collections:addFolder(d.collections, cur.payload.id, folder)};
        });
        setStack(p=>p.map(s=>{
          if(s.type!=="col") return s;
          const updateCol = (c) => {
            if(c.id===cur.payload.id) return {...c, sub:[...(c.sub||[]), folder]};
            if(c.sub) return {...c, sub:c.sub.map(updateCol)};
            return c;
          };
          return {...s, payload:updateCol(s.payload)};
        }));
      }}
      library={library}
      collections={data.collections}
      onEditCollection={updated=>{
        setData(d=>{
          const updateCol = (cols) => cols.map(c => {
            if(c.id===updated.id) return {...c,...updated};
            if(c.sub) return {...c,sub:updateCol(c.sub)};
            return c;
          });
          return {...d,collections:updateCol(d.collections)};
        });
        setStack(p=>p.map(s=>s.type==="col"&&s.payload.id===updated.id?{...s,payload:{...s.payload,...updated}}:s));
      }}
      onRemoveRecipe={(recipeId, subId, type)=>{
        setData(d=>{
          const removeFrom = (cols) => cols.map(c => {
            if(c.id===cur.payload.id) {
              if(type==="recipe") return {...c, recipes:(c.recipes||[]).filter(r=>r.id!==recipeId)};
              if(type==="sub") return {...c, sub:(c.sub||[]).filter(s=>s.id!==subId)};
            }
            if(c.sub) return {...c, sub:removeFrom(c.sub)};
            return c;
          });
          return {...d, collections:removeFrom(d.collections)};
        });
        setStack(p=>p.map(s=>{
          if(s.type!=="col") return s;
          const updateCol = (c) => {
            if(c.id===cur.payload.id) {
              if(type==="recipe") return {...c, recipes:(c.recipes||[]).filter(r=>r.id!==recipeId)};
              if(type==="sub") return {...c, sub:(c.sub||[]).filter(sb=>sb.id!==subId)};
            }
            if(c.sub) return {...c, sub:c.sub.map(updateCol)};
            return c;
          };
          return {...s, payload:updateCol(s.payload)};
        }));
      }}
      onMoveRecipe={(recipeId, fromColId, toColId)=>{
        setData(d=>{
          const recipeRef = Object.values(d.recipes).find(r=>r.id===recipeId) || {id:recipeId,title:""};
          const move = (cols) => cols.map(c => {
            let updated = {...c};
            if(c.id===fromColId) updated = {...updated, recipes:(c.recipes||[]).filter(r=>r.id!==recipeId)};
            if(c.id===toColId && !(c.recipes||[]).find(r=>r.id===recipeId))
              updated = {...updated, recipes:[...(updated.recipes||[]), {id:recipeId,title:recipeRef.title}]};
            if(c.sub) updated = {...updated, sub:move(c.sub)};
            return updated;
          });
          return {...d, collections:move(d.collections)};
        });
        setStack(p=>p.map(s=>{
          if(s.type!=="col") return s;
          const updateCol = (c) => {
            if(c.id===cur.payload.id) return {...c, recipes:(c.recipes||[]).filter(r=>r.id!==recipeId)};
            if(c.sub) return {...c, sub:c.sub.map(updateCol)};
            return c;
          };
          return {...s, payload:updateCol(s.payload)};
        }));
      }}
    />;
    if(cur.type==="recipe") return <RecipeView
      recipe={cur.payload} onBack={pop}
      onEdit={()=>setEditingRecipe(cur.payload)}
      onSaveComment={comment=>handleSaveEdit({...cur.payload,comment})}
      collections={data.collections}
      veckomatPool={data.veckomatPool}
      onAddToCollection={(colId, recipe)=>{
        setData(d=>{
          const addToCol = (cols) => cols.map(c => {
            if(c.id===colId) {
              const already = (c.recipes||[]).find(r=>r.id===recipe.id);
              if(already) return c;
              return {...c, recipes:[...(c.recipes||[]), {id:recipe.id,title:recipe.title}]};
            }
            if(c.sub) return {...c, sub:addToCol(c.sub)};
            return c;
          });
          return {...d, collections:addToCol(d.collections)};
        });
      }}
      onAddToVeckomat={(recipe)=>{
        if(!data.veckomatPool.find(r=>r.id===recipe.id))
          setData(d=>({...d, veckomatPool:[...d.veckomatPool, data.recipes[recipe.id]||recipe]}));
      }}
    />;
    if(cur.type==="allrecipes") return <AllRecipesView recipes={data.recipes} onBack={pop} onRecipeClick={openRecipe}/>
    if(cur.type==="veckomat") return <VeckomatView pool={data.veckomatPool} recipes={data.recipes} onBack={pop} onRecipeClick={openRecipe} onRemoveFromPool={handleRemoveFromPool}/>
    if(cur.type==="imglib") return <ImageLibraryView library={library} onBack={pop} onLibraryChange={handleLibraryChange}/>;
    return null;
  };
  return (
    <div style={S.root}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Libre+Baskerville:ital,wght@0,400;0,700;1,400&family=Nunito:wght@300;400;500;600;700&display=swap'); *{box-sizing:border-box;margin:0;padding:0;} ::-webkit-scrollbar{width:3px;}::-webkit-scrollbar-thumb{background:#ddd;} button{cursor:pointer;border:none;background:none;font-family:inherit;} input,textarea,select{font-family:inherit;outline:none;} @keyframes spin{to{transform:rotate(360deg);}}`}</style>
      <header style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"14px 20px",borderBottom:"1px solid #EAE6DF",position:"sticky",top:0,background:"#F7F4EE",zIndex:50}}>
        <span style={{fontFamily:"'Libre Baskerville',serif",fontSize:19,letterSpacing:.5,color:"#1a1a1a"}}>BON APP!</span>
        <div style={{display:"flex",gap:10,alignItems:"center"}}>
          <button onClick={()=>setShowImport(true)} style={{fontSize:12,color:"#1a1a1a",border:"1px solid #E8E4DD",padding:"6px 14px",borderRadius:8,background:"#fff"}}>+ Recept</button>
          <span style={{fontSize:13,color:"#1a1a1a",letterSpacing:3,textTransform:"uppercase"}}>v.{WEEK_NUM}</span>
        </div>
      </header>
      <main style={{paddingBottom:110}}>{render()}</main>
      {showAddCollection&&<AddCollectionModal
        onClose={()=>setShowAddCollection(false)}
        onSave={col=>{
          setData(d=>({...d, collections:[...d.collections, col]}));
          setShowAddCollection(false);
        }}
      />}
      {showImport&&<ImportModal onClose={()=>setShowImport(false)} onImported={handleImported} library={library} collections={data.collections}/>}
      {editingRecipe&&<EditModal recipe={editingRecipe} onClose={()=>setEditingRecipe(null)} onSave={handleSaveEdit} library={library}/>}
      <AIAssistant context={aiCtx} pool={data.veckomatPool} week={data.activeWeek} recipes={data.recipes}/>
    </div>
  );
}

// ── Shared styles ─────────────────────────────────────────────────────────────
const S = {
  root:{ background:"#F7F4EE", minHeight:"100vh", color:"#1a1a1a", fontFamily:"'Nunito',sans-serif" },
  view:{ padding:"20px" },
  eyebrow:{ fontSize:13, letterSpacing:4, color:"#1a1a1a", textTransform:"uppercase" },
  stickyBack:{ position:"fixed", top:70, left:16, zIndex:60, width:36, height:36, borderRadius:"50%", background:"rgba(247,244,238,0.92)", color:"#1a1a1a", fontSize:18, display:"flex", alignItems:"center", justifyContent:"center", backdropFilter:"blur(8px)", border:"1px solid #E8E4DD", cursor:"pointer" },
  tagChipSm:{ fontSize:12, color:"#1a1a1a", background:"#F0EDE6", border:"1px solid #EAE6DF", padding:"2px 8px", borderRadius:10 },
  tagToggle:{ fontSize:13, padding:"5px 10px", borderRadius:12, border:"1px solid #E8E4DD", color:"#1a1a1a", cursor:"pointer", background:"#fff" },
  tagToggleOn:{ background:"#F0EDE6", color:"#1a1a1a", borderColor:"#d4cfc8" },
  tagAddBtn:{ background:"#F0EDE6", color:"#1a1a1a", border:"1px solid #E8E4DD", borderRadius:8, padding:"7px 14px", fontSize:16, cursor:"pointer" },
  modalBg:{ position:"fixed", inset:0, background:"rgba(0,0,0,0.35)", display:"flex", alignItems:"flex-end", justifyContent:"center", zIndex:200 },
  modalBox:{ background:"#fff", border:"1px solid #E8E4DD", borderRadius:"16px 16px 0 0", width:"100%", maxWidth:480 },
  modalHead:{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"18px 20px", borderBottom:"1px solid #F0EDE6" },
  iconBtn:{ fontSize:15, color:"#1a1a1a", padding:4, cursor:"pointer", background:"none", border:"none" },
  formWrap:{ padding:"16px 20px 30px" },
  formGroup:{ marginBottom:18 },
  formLabel:{ fontSize:13, letterSpacing:2, color:"#1a1a1a", textTransform:"uppercase", display:"block", marginBottom:8, fontWeight:600 },
  formInput:{ width:"100%", background:"#FAFAF8", border:"1px solid #E8E4DD", borderRadius:8, padding:"10px 12px", color:"#1a1a1a", fontSize:16 },
  primaryBtn:{ width:"100%", padding:"13px", background:"#1a1a1a", color:"#F7F4EE", borderRadius:10, fontSize:14, fontWeight:600, marginTop:8, border:"none", cursor:"pointer" },
  imgUpload:{ display:"block", border:"1px dashed #E8E4DD", borderRadius:8, padding:"20px", textAlign:"center", fontSize:13, color:"#1a1a1a", cursor:"pointer" },
  imgRemove:{ position:"absolute", top:8, right:8, background:"rgba(255,255,255,0.92)", color:"#333", borderRadius:"50%", width:24, height:24, display:"flex", alignItems:"center", justifyContent:"center", fontSize:12, border:"1px solid #ddd", cursor:"pointer" },
  servingBtn:{ width:28, height:28, border:"1px solid #E8E4DD", borderRadius:"50%", color:"#1a1a1a", fontSize:16, display:"flex", alignItems:"center", justifyContent:"center", background:"#fff", cursor:"pointer" },
  metaBox:{ background:"#F7F4EE", borderRadius:10, padding:"14px 16px", marginBottom:12, marginTop:16 },
  metaTitle:{ fontSize:13, letterSpacing:1, color:"#1a1a1a", textTransform:"uppercase", marginBottom:10 },
  spinner:{ width:24, height:24, border:"2px solid #E8E4DD", borderTop:"2px solid #1a1a1a", borderRadius:"50%", animation:"spin 0.8s linear infinite" },
};
